    html += '<svg viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="' + m.color + '" stroke-width="2"><path d="M12 2a7 7 0 017 7c0 5-7 13-7 13S5 14 5 9a7 7 0 017-7z"/><circle cx="12" cy="9" r="2.5"/></svg>';
    html += '</div>';
