    html += '  <svg viewBox="0 0 24 24" width="14" height="14" fill="currentColor" style="opacity: 0.4; flex-shrink: 0;"><circle cx="5" cy="5" r="2"/><circle cx="12" cy="5" r="2"/><circle cx="5" cy="12" r="2"/><circle cx="12" cy="12" r="2"/></svg>';
