function executeExportBrand() {
  var scope = document.querySelector('input[name="exportScope"]:checked').value;
  var format = document.querySelector('input[name="exportFormat"]:checked').value;
  closeModal('exportBrandModal');

  if (format === 'json') {
    if (scope === 'all') {
      exportAllBrands();
    } else {
      exportBrandData();
    }
  } else {
    // Rich Text export
    var brandsToExport = scope === 'all' ? brands : [brands[selectedBrand]];
    var text = 'RoweOS Brand Export\n' + '='.repeat(40) + '\n';
    text += 'Exported: ' + new Date().toLocaleString() + '\n\n';
    brandsToExport.forEach(function(brand, i) {
      if (scope === 'all') text += '\n' + '-'.repeat(40) + '\n';
      text += 'BRAND: ' + (brand.name || 'Unnamed') + '\n';
      if (brand.shortName) text += 'Short Name: ' + brand.shortName + '\n';
      if (brand.tagline) text += 'Tagline: ' + brand.tagline + '\n';
      if (brand.description) text += '\nDescription:\n' + brand.description + '\n';
      if (brand.voice) text += '\nVoice & Tone:\n' + brand.voice + '\n';
      if (brand.audience) text += '\nTarget Audience:\n' + brand.audience + '\n';
      if (brand.keywords && brand.keywords.length) text += '\nKeywords: ' + (Array.isArray(brand.keywords) ? brand.keywords.join(', ') : brand.keywords) + '\n';
      // Include memory if available
      var idx = brands.indexOf(brand);
      var mem = null;
      try { mem = JSON.parse(localStorage.getItem('brand_' + idx)); } catch(e) {}
      if (mem && typeof mem === 'object') {
        var memText = typeof mem === 'string' ? mem : JSON.stringify(mem, null, 2);
        if (memText && memText.length > 2) text += '\nMemory:\n' + memText + '\n';
      }
      text += '\n';
    });
    var blob = new Blob([text], { type: 'text/plain;charset=utf-8' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url;
    a.download = (scope === 'all' ? 'RoweOS_All_Brands' : (brands[selectedBrand].name || 'Brand').replace(/\s+/g, '_')) + '_export.txt';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    showToast('Brand exported as text', 'success');
  }
}

function importBrandData(input) {
  var file = input.files[0];
  if (!file) return;
  
  var reader = new FileReader();
  reader.onload = function(e) {
    try {
      var data = JSON.parse(e.target.result);
      
      // Validate data structure
      if (!data.brand || !data.brand.name) {
        showToast('Error', 'Invalid brand data file', 'error');
        return;
      }
      
      // Check if brand already exists
      var exists = brands.some(function(b) { 
        return b.name.toLowerCase() === data.brand.name.toLowerCase(); 
      });
      
      if (exists) {
        var confirmImport = confirm('A brand named "' + data.brand.name + '" already exists. Import anyway as a duplicate?');
        if (!confirmImport) {
          input.value = '';
          return;
        }
        
        // Append " (Imported)" to avoid confusion
        data.brand.name += ' (Imported)';
      }
      
      // Add brand
      brands.push(data.brand);
      var newIdx = brands.length - 1;
      
      // Import memory if present
      if (data.memory) {
        var brandKey = 'brand_' + newIdx;
        saveToLocalStorage(brandKey, data.memory);
      }
      
      // Import model config if present
      if (data.modelConfig) {
        saveToLocalStorage('model_' + newIdx, data.modelConfig);
      }
      
      // Import files if present
      if (data.files) {
        saveToLocalStorage('files_brand_' + newIdx, data.files);
      }
      
      // Save brands
      saveToLocalStorage('brands', brands);
      
      // Update UI
      syncBrandDropdowns();
      renderMemoryBrandPills();
      renderLibraryView();
      renderGuardrailsUI();
      
      // Switch to imported brand
      selectedBrandIdx = newIdx;
      onBrandChange();
      
      // Close modal
      closeModal('importExportModal');
      
      // Show success
      showToast('Success', 'Brand "' + data.brand.name + '" imported successfully', 'success');
      
      // Clear input
      input.value = '';
      
    } catch (err) {
      showToast('Error', 'Failed to import brand: ' + err.message, 'error');
      input.value = '';
    }
  };
  
  reader.readAsText(file);
}

// v25.2: Spotlight functions (replace old openSearch/closeSearch/performGlobalSearch)
var _spotlightHighlight = -1;
var _spotlightResults = [];
var _spotlightDebounce = null;

function openSpotlight() {
  var overlay = document.getElementById('searchOverlay');
  if (!overlay) return;
  overlay.style.display = 'flex';
  document.body.style.overflow = 'hidden';
  setTimeout(function() {
    var input = document.getElementById('spotlightInput');
    if (input) { input.focus(); input.value = ''; }
    // Show recent searches
    showRecentSearches();
    updateScopeButton();
  }, 50);
  _spotlightHighlight = -1;
  _spotlightResults = [];
}
// Keep backward compat
var openSearch = openSpotlight;

function closeSpotlight() {
  var overlay = document.getElementById('searchOverlay');
  if (overlay) { overlay.style.display = 'none'; document.body.style.overflow = ''; }
}
var closeSearch = closeSpotlight;

function showRecentSearches() {
  var container = document.getElementById('spotlightResults');
  if (!container) return;
  var recent = getRecentSearches();
  if (recent.length === 0) {
    container.innerHTML = '<div class="search-empty">Type to search across all of RoweOS</div>';
    return;
  }
  var html = '<div class="search-result-group">Recent</div>';
  for (var i = 0; i < recent.length; i++) {
    html += '<div class="search-recent-item" onclick="document.getElementById(\'spotlightInput\').value=this.textContent.trim();onSpotlightInput(this.textContent.trim())">'
      + '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><path d="M12 6v6l4 2"/></svg>'
      + escapeHtml(recent[i]) + '</div>';
  }
  container.innerHTML = html;
}

function updateScopeButton() {
  var btn = document.getElementById('spotlightScopeBtn');
  if (!btn) return;
  var scope = getSearchScope();
  btn.textContent = scope.label;
}

function toggleSearchScope() {
  _searchScope = _searchScope === 'current' ? 'all' : 'current';
  updateScopeButton();
  var input = document.getElementById('spotlightInput');
  if (input && input.value.trim()) onSpotlightInput(input.value);
}

function setSearchMode(mode, btn) {
  _searchMode = mode;
  var btns = document.querySelectorAll('.search-mode-btn');
  for (var i = 0; i < btns.length; i++) btns[i].classList.remove('active');
  if (btn) btn.classList.add('active');
  var input = document.getElementById('spotlightInput');
  if (input && input.value.trim()) onSpotlightInput(input.value);
}

function onSpotlightInput(value) {
  if (_spotlightDebounce) clearTimeout(_spotlightDebounce);
  _spotlightDebounce = setTimeout(function() {
    if (!value || value.trim().length === 0) { showRecentSearches(); return; }
    executeSearch(value, _searchMode, function(results) {
      renderSpotlightResults(results);
    });
  }, 200);
}

function onSpotlightKeydown(e) {
  if (e.key === 'Escape') { closeSpotlight(); return; }
  if (e.key === 'Tab') {
    e.preventDefault();
    var modes = ['ai', 'navigate', 'actions'];
    var idx = modes.indexOf(_searchMode);
    var next = modes[(idx + 1) % modes.length];
    var btn = document.querySelector('.search-mode-btn[data-mode="' + next + '"]');
    setSearchMode(next, btn);
    return;
  }
  var items = document.querySelectorAll('#spotlightResults .search-result-item');
  if (e.key === 'ArrowDown') {
    e.preventDefault();
    _spotlightHighlight = Math.min(_spotlightHighlight + 1, items.length - 1);
    highlightSpotlightItem(items);
  } else if (e.key === 'ArrowUp') {
    e.preventDefault();
    _spotlightHighlight = Math.max(_spotlightHighlight - 1, -1);
    highlightSpotlightItem(items);
  } else if (e.key === 'Enter') {
    if (_spotlightHighlight >= 0 && _spotlightHighlight < _spotlightResults.length) {
      var result = _spotlightResults[_spotlightHighlight];
      if (result && typeof result.action === 'function') { result.action(); closeSpotlight(); }
    }
  }
}

function highlightSpotlightItem(items) {
  for (var i = 0; i < items.length; i++) {
    items[i].classList.toggle('highlighted', i === _spotlightHighlight);
  }
}

function renderSpotlightResults(data) {
  var container = document.getElementById('spotlightResults');
  if (!container) return;
  _spotlightResults = [];
  _spotlightHighlight = -1;
  var html = '';

  // AI response
  if (data.ai && data.ai.text) {
    var mode = _bloomSource && _bloomSource.indexOf('life_') === 0 ? 'LifeAI' : 'BrandAI';
    html += '<div class="search-ai-response">'
      + '<div class="search-ai-header">'
      + '<div class="search-ai-avatar">' + mode.charAt(0) + '</div>'
      + '<span class="search-ai-label">' + mode + '</span>'
      + '</div>'
      + '<div class="search-ai-text">' + escapeHtml(data.ai.text).substring(0, 300) + '</div>'
      + '</div>';
  }

  // Navigation results
  var navItems = data.nav || [];
  var actionItems = data.actions || [];
  var allItems = actionItems.concat(navItems);

  if (allItems.length > 0) {
    var groupLabel = actionItems.length > 0 ? 'Actions' : 'Results';
    html += '<div class="search-result-group">' + groupLabel + '</div>';
    for (var i = 0; i < Math.min(allItems.length, 6); i++) {
      var item = allItems[i];
      _spotlightResults.push(item);
      var typeLabel = item.type || 'result';
      html += '<div class="search-result-item" onclick="_spotlightResults[' + (_spotlightResults.length - 1) + '].action();closeSpotlight()">'
        + '<span class="search-result-type">' + typeLabel + '</span>'
        + '<span class="search-result-title">' + escapeHtml(item.title) + '</span>'
        + '<span class="search-result-desc">' + escapeHtml(item.desc || '') + '</span>'
        + '</div>';
    }
  }

  if (!html) html = '<div class="search-empty">No results found</div>';
  container.innerHTML = html;
}

// v25.2: Universal Search Engine
var _searchMode = 'ai'; // 'ai', 'navigate', 'actions'
var _searchScope = 'current'; // 'current' or 'all'
var _searchRecentKey = 'roweos_recent_searches';

function getSearchScope() {
  if (_searchScope === 'all') return { brands: brands, label: 'All Brands' };
  var idx = selectedBrand || 0;
  return { brands: brands[idx] ? [brands[idx]] : brands, brandIdx: idx, label: (brands[idx] || {}).shortName || (brands[idx] || {}).name || 'Current Brand' };
}

function addRecentSearch(query) {
  if (!query || query.trim().length < 2) return;
  var recent = [];
  try { recent = JSON.parse(localStorage.getItem(_searchRecentKey) || '[]'); } catch(e) {}
  recent = recent.filter(function(r) { return r !== query; });
  recent.unshift(query);
  if (recent.length > 10) recent = recent.slice(0, 10);
  localStorage.setItem(_searchRecentKey, JSON.stringify(recent));
}

function getRecentSearches() {
  try { return JSON.parse(localStorage.getItem(_searchRecentKey) || '[]'); } catch(e) { return []; }
}

function executeSearch(query, mode, callback) {
  if (!query || query.trim().length === 0) { callback([]); return; }
  query = query.trim();
  addRecentSearch(query);
  mode = mode || _searchMode;

  if (mode === 'ai') {
    searchWithAI(query, function(aiResults) {
      // Also include navigation results as fallback
      var navResults = searchNavigate(query);
      callback({ ai: aiResults, nav: navResults.slice(0, 4) });
    });
  } else if (mode === 'actions') {
    var actionResults = searchActions(query);
    var navResults = searchNavigate(query);
    callback({ actions: actionResults, nav: navResults.slice(0, 4) });
  } else {
    var navResults = searchNavigate(query);
    callback({ nav: navResults });
  }
}

function fuzzyMatch(text, query) {
  if (!text || !query) return false;
  text = text.toLowerCase();
  query = query.toLowerCase();
  // Substring match
  if (text.indexOf(query) !== -1) return true;
  // Word-boundary match (each query word appears somewhere)
  var words = query.split(/\s+/);
  var allFound = true;
  for (var w = 0; w < words.length; w++) {
    if (text.indexOf(words[w]) === -1) { allFound = false; break; }
  }
  return allFound;
}

function searchNavigate(query) {
  var results = [];
  var q = query.toLowerCase().trim();
  var scope = getSearchScope();

  // 1. Features/Views
  var views = [
    { name: 'BrandAI', view: 'signal', icon: 'chat', desc: 'AI-powered brand assistant' },
    { name: 'Focus', view: 'signal', section: 'focus', icon: 'focus', desc: 'Tasks, calendar, and daily planning' },
    { name: 'Bloom', view: 'bloom', icon: 'bloom', desc: 'AI content feed' },
    { name: 'Pulse', view: 'pulse', icon: 'pulse', desc: 'Goals and progress tracking' },
    { name: 'Studio', view: 'studio', icon: 'studio', desc: 'Content creation workspace' },
    { name: 'Mail', view: 'mail', icon: 'mail', desc: 'Email composition and management' },
    { name: 'Rhythm', view: 'rhythm', icon: 'rhythm', desc: 'Calendar and scheduling' },
    { name: 'Library', view: 'library', icon: 'library', desc: 'Files and documents' },
    { name: 'Automations', view: 'automations', icon: 'automations', desc: 'Workflows and pipelines' },
    { name: 'Identity', view: 'identity', icon: 'identity', desc: 'Brand voice and identity' },
    { name: 'Clients', view: 'clients', icon: 'clients', desc: 'Contacts and CRM' },
    { name: 'Settings', view: 'settings', icon: 'settings', desc: 'App configuration' },
    { name: 'Sync', view: 'sync', icon: 'sync', desc: 'Cloud sync and backup' },
    { name: 'Analytics', view: 'analytics', icon: 'analytics', desc: 'Usage and performance' }
  ];
  for (var vi = 0; vi < views.length; vi++) {
    if (fuzzyMatch(views[vi].name + ' ' + views[vi].desc, q)) {
      results.push({ type: 'feature', title: views[vi].name, desc: views[vi].desc, action: function(v) { return function() { showView(v.view); if (v.section) showScreen(v.section); }; }(views[vi]) });
    }
  }

  // 2. Brands
  for (var bi = 0; bi < brands.length; bi++) {
    var b = brands[bi];
    var bText = (b.name || '') + ' ' + (b.shortName || '') + ' ' + (b.tagline || '') + ' ' + (b.industry || '');
    if (fuzzyMatch(bText, q)) {
      results.push({ type: 'brand', title: b.shortName || b.name, desc: b.tagline || b.industry || 'Brand', action: function(idx) { return function() { selectedBrand = idx; localStorage.setItem('roweos_selected_brand', String(idx)); if (typeof applyCurrentBrandAccent === 'function') applyCurrentBrandAccent(); showView('signal'); }; }(bi) });
    }
  }

  // 3. Clients
  try {
    var clients = JSON.parse(localStorage.getItem('roweos_clients') || '[]');
    for (var ci = 0; ci < clients.length; ci++) {
      var c = clients[ci];
      if (fuzzyMatch((c.name || '') + ' ' + (c.company || '') + ' ' + (c.email || ''), q)) {
        results.push({ type: 'client', title: c.name || 'Client', desc: c.company || c.email || '', action: function() { showView('clients'); } });
      }
    }
  } catch(e) {}

  // 4. Automations
  try {
    var autos = JSON.parse(localStorage.getItem('roweos_automations') || '[]');
    for (var ai2 = 0; ai2 < autos.length; ai2++) {
      var a = autos[ai2];
      if (fuzzyMatch(a.name || '', q)) {
        results.push({ type: 'automation', title: a.name, desc: 'Automation', action: function() { showView('automations'); } });
      }
    }
  } catch(e) {}

  // 5. Pulse goals
  try {
    var goals = JSON.parse(localStorage.getItem('roweos_pulse_goals') || '[]');
    for (var gi = 0; gi < goals.length; gi++) {
      var g = goals[gi];
      if (fuzzyMatch(g.name || '', q)) {
        results.push({ type: 'goal', title: g.name, desc: 'Pulse Goal', action: function() { showView('pulse'); } });
      }
    }
  } catch(e) {}

  // 6. Calendar events
  try {
    var cal = JSON.parse(localStorage.getItem('roweos_calendar') || '[]');
    for (var ei = 0; ei < Math.min(cal.length, 50); ei++) {
      if (fuzzyMatch(cal[ei].title || '', q)) {
        results.push({ type: 'event', title: cal[ei].title, desc: (cal[ei].date || '') + ' ' + (cal[ei].time || ''), action: function() { showView('rhythm'); } });
      }
    }
  } catch(e) {}

  // 7. Library items
  try {
    var lib = JSON.parse(localStorage.getItem('roweosLibrary') || '{}');
    if (lib.files) {
      for (var fi = 0; fi < lib.files.length; fi++) {
        if (fuzzyMatch(lib.files[fi].name || '', q)) {
          results.push({ type: 'file', title: lib.files[fi].name, desc: 'Library', action: function() { showView('library'); } });
        }
      }
    }
  } catch(e) {}

  return results.slice(0, 20);
}

function searchActions(query) {
  var results = [];
  var q = query.toLowerCase().trim();

  // Pattern: "new email to {name}" or "email {name}"
  var emailMatch = q.match(/^(?:new )?(?:email|mail|compose|write)(?: to)? (.+)/i);
  if (emailMatch) {
    var recipient = emailMatch[1].trim();
    results.push({ type: 'action', title: 'Compose email to ' + recipient, desc: 'Opens Mail composer', action: function() { showView('mail'); if (typeof showMailTab === 'function') showMailTab('compose'); } });
  }

  // Pattern: "run {automation}" or "execute {automation}"
  var runMatch = q.match(/^(?:run|execute|start|trigger) (.+)/i);
  if (runMatch) {
    var autoName = runMatch[1].trim();
    try {
      var autos = JSON.parse(localStorage.getItem('roweos_automations') || '[]');
      for (var i = 0; i < autos.length; i++) {
        if (fuzzyMatch(autos[i].name || '', autoName)) {
          results.push({ type: 'action', title: 'Run "' + autos[i].name + '"', desc: 'Execute automation', action: function(auto) { return function() { if (typeof runAutomationNow === 'function') runAutomationNow(auto); }; }(autos[i]) });
        }
      }
    } catch(e) {}
  }

  // Pattern: "add goal {text}" or "new goal {text}"
  var goalMatch = q.match(/^(?:add|new|create) (?:goal|pulse goal) (.+)/i);
  if (goalMatch) {
    var goalText = goalMatch[1].trim();
    results.push({ type: 'action', title: 'Add Pulse goal: "' + goalText + '"', desc: 'Creates a new goal', action: function() { showView('pulse'); } });
  }

  // Pattern: "new task {text}" or "add task {text}"
  var taskMatch = q.match(/^(?:add|new|create) (?:task|todo|focus) (.+)/i);
  if (taskMatch) {
    results.push({ type: 'action', title: 'Add Focus task: "' + taskMatch[1].trim() + '"', desc: 'Creates a new task', action: function() { showView('signal'); if (typeof showScreen === 'function') showScreen('focus'); } });
  }

  // Pattern: "open {feature}"
  var openMatch = q.match(/^(?:open|go to|show|switch to) (.+)/i);
  if (openMatch) {
    var navResults = searchNavigate(openMatch[1]);
    for (var ni = 0; ni < Math.min(navResults.length, 3); ni++) {
      navResults[ni].type = 'action';
      navResults[ni].title = 'Open ' + navResults[ni].title;
      results.push(navResults[ni]);
    }
  }

  // Pattern: "new automation" or "create automation"
  if (/^(?:new|create|add) automation/i.test(q)) {
    results.push({ type: 'action', title: 'Create new automation', desc: 'Opens automation builder', action: function() { showView('automations'); } });
  }

  return results;
}

function searchWithAI(query, callback) {
  var scope = getSearchScope();
  var brandName = scope.brands[0] ? (scope.brands[0].shortName || scope.brands[0].name) : 'RoweOS';

  // Build context summary for AI
  var context = 'You are a search assistant for RoweOS, a brand intelligence platform. ';
  context += 'Current brand: ' + brandName + '. ';

  // Add data summaries
  try {
    var goals = JSON.parse(localStorage.getItem('roweos_pulse_goals') || '[]');
    if (goals.length > 0) context += 'Pulse goals: ' + goals.map(function(g) { return g.name; }).join(', ') + '. ';
  } catch(e) {}
  try {
    var autos = JSON.parse(localStorage.getItem('roweos_automations') || '[]');
    if (autos.length > 0) context += 'Automations: ' + autos.map(function(a) { return a.name; }).join(', ') + '. ';
  } catch(e) {}
  try {
    var clients = JSON.parse(localStorage.getItem('roweos_clients') || '[]');
    if (clients.length > 0) context += 'Clients: ' + clients.slice(0, 10).map(function(c) { return c.name + (c.company ? ' (' + c.company + ')' : ''); }).join(', ') + '. ';
  } catch(e) {}
  try {
    var sent = JSON.parse(localStorage.getItem('roweos_mail_sent') || '[]');
    if (sent.length > 0) context += 'Recent sent emails: ' + sent.slice(0, 5).map(function(m) { return '"' + (m.subject || 'No subject') + '" to ' + (m.to || 'unknown'); }).join(', ') + '. ';
  } catch(e) {}

  var systemPrompt = context + 'Answer the user\'s search query concisely. If they ask about their data (goals, emails, clients, automations), reference the specific items. Keep responses under 150 words. Never use em-dashes. Use plain language.';

  // Get API settings
  var brandIdx = selectedBrand || 0;
  var provider = 'anthropic';
  var model = 'claude-sonnet-4-6';
  var apiKey = '';
  try {
    var bSettings = (typeof brandSettings !== 'undefined' && brandSettings[brandIdx]) ? brandSettings[brandIdx] : {};
    provider = bSettings.provider || 'anthropic';
    model = bSettings.model || 'claude-sonnet-4-6';
    apiKey = getApiKey(provider);
    if (provider === 'roweos' && typeof resolveRoweOSAI === 'function') {
      var resolved = resolveRoweOSAI({ userMessage: query, systemPrompt: systemPrompt });
      provider = resolved.provider;
      model = resolved.model;
      apiKey = resolved.apiKey || getApiKey(resolved.provider);
    }
  } catch(e) {}

  if (!apiKey) {
    callback({ text: 'No API key configured. Switch to Navigate mode for local search.', results: [] });
    return;
  }

  var messages = [{ role: 'user', content: query }];

  if (typeof callAnthropicChat === 'function' && provider === 'anthropic') {
    callAnthropicChat(model, apiKey, messages, systemPrompt, function(response) {
      callback({ text: response, results: [] });
    }, function(err) {
      callback({ text: 'Search failed. Try Navigate mode.', results: [] });
    });
  } else if (typeof callOpenAIChat === 'function' && provider === 'openai') {
    callOpenAIChat(model, apiKey, messages, systemPrompt, function(response) {
      callback({ text: response, results: [] });
    }, function(err) {
      callback({ text: 'Search failed. Try Navigate mode.', results: [] });
    });
  } else {
    // Fallback to navigate
    callback({ text: null, results: searchNavigate(query) });
  }
}

// Keep backward compat
function performGlobalSearch(q) { onSpotlightInput(q); }

// v25.2: Search Side Panel
function openSearchPanel(tab) {
  var panel = document.getElementById('searchSidePanel');
  var scrim = document.getElementById('searchSideScrim');
  if (panel) panel.classList.add('open');
  if (scrim) scrim.classList.add('open');
  if (tab === 'notifications') {
    switchSidePanelTab('notifications', document.querySelector('.search-side-tab[data-tab="notifications"]'));
  } else {
    switchSidePanelTab('search', document.querySelector('.search-side-tab[data-tab="search"]'));
    setTimeout(function() {
      var input = document.getElementById('sidePanelSearchInput');
      if (input) input.focus();
    }, 100);
  }
}

function closeSearchPanel() {
  var panel = document.getElementById('searchSidePanel');
  var scrim = document.getElementById('searchSideScrim');
  if (panel) panel.classList.remove('open');
  if (scrim) scrim.classList.remove('open');
}

function switchSidePanelTab(tab, btn) {
  var tabs = document.querySelectorAll('.search-side-tab');
  for (var i = 0; i < tabs.length; i++) tabs[i].classList.remove('active');
  if (btn) btn.classList.add('active');
  var searchView = document.getElementById('sidePanelSearchView');
  var notiView = document.getElementById('sidePanelNotificationsView');
  if (tab === 'search') {
    if (searchView) searchView.style.display = '';
    if (notiView) notiView.style.display = 'none';
  } else {
    if (searchView) searchView.style.display = 'none';
    if (notiView) { notiView.style.display = ''; notiView.style.flex = '1'; }
    renderSidePanelNotifications();
  }
}

var _sidePanelDebounce = null;
function onSidePanelSearch(value) {
  if (_sidePanelDebounce) clearTimeout(_sidePanelDebounce);
  _sidePanelDebounce = setTimeout(function() {
    if (!value || value.trim().length === 0) {
      var container = document.getElementById('sidePanelResults');
      if (container) container.innerHTML = '<div style="text-align:center;padding:24px;color:var(--text-tertiary);font-size:13px;">Search across all of RoweOS</div>';
      return;
    }
    // Try AI first, fall back to navigate
    executeSearch(value, 'ai', function(results) {
      if ((!results.ai || !results.ai.text) && (!results.nav || results.nav.length === 0)) {
        // AI returned nothing, try navigate mode
        var navResults = searchNavigate(value);
        renderSidePanelResults({ nav: navResults });
      } else {
        renderSidePanelResults(results);
      }
    });
  }, 300);
}

function renderSidePanelResults(data) {
  var container = document.getElementById('sidePanelResults');
  if (!container) return;
  window._sidePanelActions = [];
  var html = '';

  if (data.ai && data.ai.text) {
    var mode = typeof _lifeMode !== 'undefined' && _lifeMode ? 'LifeAI' : 'BrandAI';
    html += '<div style="margin-bottom:16px;">'
      + '<div style="display:flex;align-items:center;gap:6px;margin-bottom:8px;">'
      + '<div style="width:20px;height:20px;background:var(--accent);border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:9px;color:#000;font-weight:700;">' + mode.charAt(0) + '</div>'
      + '<span style="font-size:11px;color:var(--accent);font-weight:600;">' + mode + '</span></div>'
      + '<div style="font-size:13px;color:var(--text-secondary);line-height:1.7;">' + escapeHtml(data.ai.text) + '</div>'
      + '</div>';
  }

  var navItems = data.nav || [];
  var actionItems = data.actions || [];
  var allItems = actionItems.concat(navItems);
  if (allItems.length > 0) {
    for (var i = 0; i < allItems.length; i++) {
      var item = allItems[i];
      window._sidePanelActions.push(item.action);
      html += '<div style="background:var(--bg-secondary);border:1px solid var(--border-color);border-radius:8px;padding:10px 12px;margin-bottom:6px;cursor:pointer;" onclick="closeSearchPanel();if(window._sidePanelActions[' + i + '])window._sidePanelActions[' + i + ']()">'
        + '<div style="font-size:12px;color:var(--text-primary);">' + escapeHtml(item.title) + '</div>'
        + '<div style="font-size:10px;color:var(--text-tertiary);margin-top:2px;">' + escapeHtml(item.desc || '') + '</div>'
        + '</div>';
    }
  }

  if (!html) html = '<div style="text-align:center;padding:24px;color:var(--text-tertiary);font-size:13px;">No results found</div>';
  container.innerHTML = html;
}

function renderSidePanelNotifications() {
  var container = document.getElementById('sidePanelNotificationsView');
  if (!container) return;
  // Reuse existing notification panel content
  var ncPanel = document.getElementById('notificationCenterPanel');
  if (ncPanel) {
    container.innerHTML = ncPanel.innerHTML;
  } else {
    container.innerHTML = '<div style="text-align:center;padding:24px;color:var(--text-tertiary);font-size:13px;">No notifications</div>';
  }
}

function _performGlobalSearch_legacy(query) {
  var resultsContainer = document.getElementById('searchResults');

  if (!query || query.trim().length === 0) {
    if (resultsContainer) resultsContainer.innerHTML = '<div class="search-empty">Type to search across all brands, memory, files, and conversations</div>';
    return;
  }
  
  query = query.toLowerCase().trim();
  var results = [];
  
  // Search views/features
  var views = [
    {name: 'BrandAI', view: 'signal', desc: 'AI-powered brand assistant'},
    {name: 'Focus', view: 'signal', desc: 'Signal processing and brand insights'},
    {name: 'Pulse', view: 'pulse', desc: 'Brand health dashboard'},
    {name: 'Studio', view: 'studio', desc: 'Content creation workspace'},
    {name: 'Rhythm', view: 'rhythm', desc: 'Calendar and scheduling'},
    {name: 'Library', view: 'library', desc: 'File management'},
    {name: 'Intelligence', view: 'identity', desc: 'Brand configuration'},
    {name: 'Tuning', view: 'tuning', desc: 'System configuration'},
    {name: 'Memory', view: 'memory', desc: 'Brand memory and context'},
    {name: 'Export', view: 'export', desc: 'Export brand data'},
    {name: 'Guardrails', view: 'guardrails', desc: 'Content guidelines'}
  ];
  
  views.forEach(function(v) {
    if (v.name.toLowerCase().includes(query) || v.desc.toLowerCase().includes(query)) {
      results.push({
        title: v.name,
        path: 'View / ' + v.desc,
        action: function() {
          showView(v.view);
          closeSearch();
        }
      });
    }
  });
  
  // Search brands
  brands.forEach(function(brand, idx) {
    if (brand.name.toLowerCase().includes(query)) {
      results.push({
        title: brand.name,
        path: 'Brand / Identity',
        action: function() { 
          selectedBrandIdx = idx; 
          onBrandChange(); 
          showView('identity'); 
          closeSearch(); 
        }
      });
    }
    
    if (brand.tagline && brand.tagline.toLowerCase().includes(query)) {
      results.push({
        title: brand.tagline,
        path: 'Brand / ' + brand.name + ' / Tagline',
        action: function() { 
          selectedBrandIdx = idx; 
          onBrandChange(); 
          showView('identity'); 
          closeSearch(); 
        }
      });
    }
  });
  
  // Search memory
  Object.keys(localStorage).forEach(function(key) {
    if (key.startsWith('brand_')) {
      try {
        var data = JSON.parse(localStorage.getItem(key));
        if (data && typeof data === 'object') {
          Object.keys(data).forEach(function(field) {
            var value = data[field];
            if (value && typeof value === 'string' && value.toLowerCase().includes(query)) {
              var brandIdx = parseInt(key.split('_')[1]);
              var brandName = brands[brandIdx] ? brands[brandIdx].name : 'Unknown';
              results.push({
                title: field.charAt(0).toUpperCase() + field.slice(1),
                path: 'Memory / ' + brandName,
                action: function() { 
                  selectedBrandIdx = brandIdx; 
                  selectBrandPill(null, key); 
                  showView('memory'); 
                  closeSearch(); 
                }
              });
            }
          });
        }
      } catch (e) {}
    }
  });
  
  // v24.27: Search conversations
  try {
    var convos = JSON.parse(localStorage.getItem('roweos_conversations') || '[]');
    for (var ci = 0; ci < convos.length && results.length < 30; ci++) {
      var c = convos[ci];
      var cTitle = c.title || '';
      var cFirst = (c.conversation && c.conversation[0]) ? (c.conversation[0].displayContent || (typeof c.conversation[0].content === 'string' ? c.conversation[0].content : '')) : '';
      if ((cTitle.toLowerCase().indexOf(query) !== -1) || (cFirst.toLowerCase().indexOf(query) !== -1)) {
        results.push({ title: cTitle || cFirst.substring(0, 60), path: 'Chat History', action: (function(idx) { return function() { closeSearch(); showView('agent'); if (typeof loadConversation === 'function') loadConversation(idx); }; })(ci) });
      }
    }
  } catch(e) {}

  // v24.27: Search library
  try {
    var lib = JSON.parse(localStorage.getItem('roweos_library') || '[]');
    for (var li = 0; li < lib.length && results.length < 30; li++) {
      var item = lib[li];
      if ((item.title && item.title.toLowerCase().indexOf(query) !== -1) || (item.content && item.content.toLowerCase().indexOf(query) !== -1)) {
        results.push({ title: item.title || 'Library Item', path: 'Library' + (item.folder ? ' / ' + item.folder : ''), action: (function(id) { return function() { closeSearch(); showView('library'); }; })(item.id) });
      }
    }
  } catch(e) {}

  // v24.27: Search automations
  try {
    var autos = JSON.parse(localStorage.getItem('roweos_automations') || '[]');
    for (var ai = 0; ai < autos.length && results.length < 30; ai++) {
      var a = autos[ai];
      if ((a.name && a.name.toLowerCase().indexOf(query) !== -1) || (a.description && a.description.toLowerCase().indexOf(query) !== -1)) {
        results.push({ title: a.name || 'Automation', path: 'Automations' + (a.enabled ? '' : ' (disabled)'), action: function() { closeSearch(); showView('automations'); } });
      }
    }
  } catch(e) {}

  // v24.27: Search clients
  try {
    var clients = JSON.parse(localStorage.getItem('roweos_clients') || '[]');
    for (var cli = 0; cli < clients.length && results.length < 30; cli++) {
      var cl = clients[cli];
      if ((cl.name && cl.name.toLowerCase().indexOf(query) !== -1) || (cl.company && cl.company.toLowerCase().indexOf(query) !== -1) || (cl.email && cl.email.toLowerCase().indexOf(query) !== -1)) {
        results.push({ title: cl.name || cl.company || 'Client', path: 'Clients' + (cl.company ? ' / ' + cl.company : ''), action: function() { closeSearch(); showView('clients'); } });
      }
    }
  } catch(e) {}

  // Store results globally for click handlers
  window.currentSearchResults = results;
  
  // Display results
  if (results.length === 0) {
    resultsContainer.innerHTML = '<div class="search-empty">No results found for "' + query + '"</div>';
  } else {
    var html = '';
    results.slice(0, 20).forEach(function(result, idx) {
      html += '<div class="search-result-item" onclick="executeSearchResult(' + idx + ')" style="cursor: pointer;">';
      html += '<div class="search-result-title">' + result.title + '</div>';
      html += '<div class="search-result-path">' + result.path + '</div>';
      html += '</div>';
    });
    resultsContainer.innerHTML = html;
  }
}

// Execute search result action
function executeSearchResult(idx) {
  console.log('=== v2.81.0: executeSearchResult(' + idx + ') ===');
  
  if (window.currentSearchResults && window.currentSearchResults[idx]) {
    var result = window.currentSearchResults[idx];
    console.log('Executing action for:', result.title);
    
    if (result.action && typeof result.action === 'function') {
      result.action();
      // Show success toast
      showToast(result.title, 'Navigated', 'success');
    } else {
      console.error('No action function found for result');
    }
  } else {
    console.error('Search result not found at index:', idx);
  }
}

// Keyboard Shortcuts
function openShortcuts() {
  var panel = document.getElementById('shortcutsPanel');
  if (panel) {
    panel.style.display = 'flex';
    document.body.style.overflow = 'hidden';
  }
}

function closeShortcuts() {
  var panel = document.getElementById('shortcutsPanel');
  if (panel) {
    panel.style.display = 'none';
    document.body.style.overflow = '';
  }
}

// Enhanced Toast Notifications (handles both 2-param and 3-param calls)
function showToast(arg1, arg2, arg3) {
  // Detect call pattern: showToast(message, type) or showToast(title, message, type)
  var title, message, type;
  var validTypes = ['success', 'error', 'warning', 'info'];
  
  if (validTypes.indexOf(arg2) >= 0 && !arg3) {
    // 2-param call: showToast(message, type)
    title = null;
    message = arg1;
    type = arg2;
  } else {
    // 3-param call: showToast(title, message, type)
    title = arg1;
    message = arg2;
    type = arg3 || 'info';
  }
  
  type = type || 'info';

  // v23.5: ADHD — make error messages user-friendly
  if (type === 'error' && message && typeof friendlyError === 'function') {
    message = friendlyError(message);
  }

  var container = document.getElementById('toastContainer');
  if (!container) {
    container = document.createElement('div');
    container.id = 'toastContainer';
    container.className = 'toast-container';
    document.body.appendChild(container);
  }
  
  // Icon based on type
  var icon = '';
  if (type === 'success') {
    icon = '<svg class="toast-icon" style="color: var(--success);" viewBox="0 0 24 24"><path d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" stroke="currentColor" stroke-width="2" fill="none"/></svg>';
  } else if (type === 'error') {
    icon = '<svg class="toast-icon" style="color: var(--error);" viewBox="0 0 24 24"><path d="M10 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2m7-2a9 9 0 11-18 0 9 9 0 0118 0z" stroke="currentColor" stroke-width="2" fill="none"/></svg>';
  } else if (type === 'warning') {
    icon = '<svg class="toast-icon" style="color: var(--warning);" viewBox="0 0 24 24"><path d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" stroke="currentColor" stroke-width="2" fill="none"/></svg>';
  } else {
    icon = '<svg class="toast-icon" style="color: var(--accent);" viewBox="0 0 24 24"><path d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" stroke="currentColor" stroke-width="2" fill="none"/></svg>';
  }
  
  var toast = document.createElement('div');
  toast.className = 'toast ' + type;
  
  // Build HTML based on whether we have a title
  if (title) {
    toast.innerHTML = icon + '<div class="toast-content"><div class="toast-title">' + title + '</div><div class="toast-message">' + message + '</div></div>';
  } else {
    toast.innerHTML = icon + '<div class="toast-content"><div class="toast-message">' + message + '</div></div>';
  }
  
  container.appendChild(toast);
  
  // Trigger animation
  requestAnimationFrame(function() {
    toast.classList.add('show');
  });
  
  // Auto remove after 3.5 seconds (v9.1.14 - reduced from 7s)
  setTimeout(function() {
    toast.classList.remove('show');
    setTimeout(function() {
      if (toast.parentNode) {
        toast.parentNode.removeChild(toast);
      }
    }, 300);
  }, 3500);
}

// ═══════════════════════════════════════════════════════════════
// v24.25: REMINDERS SYSTEM
// ═══════════════════════════════════════════════════════════════

// v25.2: Show simple notification popup for automations/pipelines (old v24.25 style)
function showNotificationPopup(opts) {
  var id = 'reminderPopup_' + Date.now();
  var title = opts.title || 'Reminder';
  var message = opts.message || '';
  var actionLabel = opts.actionLabel || '';
  var actionView = opts.actionView || '';
  var source = opts.source || '';

  // Remove any existing reminder popup
  var existing = document.querySelectorAll('.reminder-popup');
  for (var e = 0; e < existing.length; e++) existing[e].remove();

  var html = '<div id="' + id + '" class="reminder-popup" style="position:fixed;bottom:20px;right:20px;z-index:99999;background:var(--bg-secondary);border:1px solid var(--brand-accent, #a89878);border-radius:var(--radius-lg);padding:16px 20px;max-width:400px;min-width:300px;box-shadow:0 8px 32px rgba(0,0,0,0.3);animation:fadeIn 0.3s ease;">';
  // Header
  html += '<div style="display:flex;align-items:center;gap:8px;margin-bottom:10px;">';
  html += '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="var(--brand-accent, #a89878)" stroke-width="2"><path d="M18 8A6 6 0 006 8c0 7-3 9-3 9h18s-3-2-3-9"/><path d="M13.73 21a2 2 0 01-3.46 0"/></svg>';
  html += '<span style="font-weight:600;font-size:14px;color:var(--text-primary);">' + escapeHtml(title) + '</span>';
  html += '<button onclick="dismissNotificationPopup(\'' + id + '\')" style="margin-left:auto;border:none;background:none;color:var(--text-muted);cursor:pointer;padding:2px;"><svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" stroke-width="2"><path d="M18 6L6 18M6 6l12 12"/></svg></button>';
  html += '</div>';
  // Body
  if (message) {
    html += '<p style="font-size:13px;color:var(--text-secondary);margin-bottom:12px;line-height:1.5;">' + escapeHtml(message) + '</p>';
  }
  // Time
  var now = new Date();
  var timeStr = now.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' });
  html += '<div style="font-size:11px;color:var(--text-muted);margin-bottom:12px;">' + timeStr + (source ? ' - via ' + source : '') + '</div>';
  // Action buttons - primary row
  html += '<div style="display:flex;gap:8px;margin-bottom:6px;">';
  if (actionLabel && actionView) {
    html += '<button onclick="dismissNotificationPopup(\'' + id + '\');if(typeof showView===\'function\')showView(\'' + escapeHtml(actionView) + '\')" style="flex:1;padding:8px;background:var(--brand-accent, #a89878);color:#000;border:none;border-radius:var(--radius-md);font-weight:600;font-size:13px;cursor:pointer;">' + escapeHtml(actionLabel) + '</button>';
  }
  html += '<button onclick="dismissNotificationPopup(\'' + id + '\')" style="flex:1;padding:8px;background:var(--bg-tertiary);color:var(--text-primary);border:1px solid var(--border-color);border-radius:var(--radius-md);font-size:13px;cursor:pointer;">Dismiss</button>';
  html += '</div>';

  document.body.insertAdjacentHTML('beforeend', html);

  // Auto-dismiss after 30 seconds
  setTimeout(function() {
    var el = document.getElementById(id);
    if (el) el.remove();
  }, 30000);

  // Play notification sound if available
  try {
    if (typeof Notification !== 'undefined' && Notification.permission === 'granted') {
      new Notification(title, { body: message || '', icon: '/favicon.ico' });
    }
  } catch(e) {}
}

// v25.2: Dismiss notification popup by element ID (for showNotificationPopup)
function dismissNotificationPopup(id) {
  var el = document.getElementById(id);
  if (el) el.remove();
}

function reminderAction(id, viewName) {
  dismissReminderPopup(id);
  if (viewName && typeof showView === 'function') {
    showView(viewName);
  }
}

// v24.26: Snooze reminder - reschedule 15 minutes later
function snoozeReminderPopup(id, title, message, source) {
  dismissReminderPopup(id);
  showToast('Snoozed for 15 minutes', 'info');
  setTimeout(function() {
    showNotificationPopup({
      title: title || 'Reminder',
      message: message || '',
      source: source || 'snoozed'
    });
  }, 15 * 60 * 1000);
}

// v24.26: Complete/dismiss reminder and mark in history
function completeReminderPopup(id) {
  dismissReminderPopup(id);
  showToast('Reminder completed', 'success');
}

// v24.26: Open BrandAI chat with reminder context
function talkToBrandAIFromReminder(id, context) {
  dismissReminderPopup(id);
  if (typeof showView === 'function') {
    showView('brand-ai');
  }
  // Pre-fill the chat input with reminder context if available
  setTimeout(function() {
    var chatInput = document.getElementById('brandAIChatInput') || document.getElementById('aiChatInput');
    if (chatInput) {
      chatInput.value = 'Regarding this reminder: ' + (context || '');
      chatInput.focus();
    }
  }, 300);
}

// Reminder history storage
function getReminders() {
  try { var _r = JSON.parse(localStorage.getItem('roweos_reminders') || '[]'); return Array.isArray(_r) ? _r : []; } catch(e) { return []; }
}

function saveReminders(reminders) {
  try {
    localStorage.setItem('roweos_reminders', JSON.stringify(reminders));
    writeDB('pulse/main', { reminders: JSON.stringify(reminders) }, { category: 'goals' }); // v25.1
  } catch(e) {}
}

function saveReminderToHistory(reminder) {
  var reminders = getReminders();
  reminder.id = 'rem_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6);
  // v25.2: New data model
  if (!reminder.status) reminder.status = 'pending';
  if (!reminder.createdAt) reminder.createdAt = Date.now();
  if (!reminder.scheduledAt && reminder.timestamp) {
    reminder.scheduledAt = new Date(reminder.timestamp).getTime();
  }
  if (!reminder.scheduledAt) reminder.scheduledAt = Date.now();
  reminder._modifiedAt = Date.now();
  reminder.snoozedUntil = null;
  reminder.actions = [];
  reminders.unshift(reminder);
  if (reminders.length > 100) reminders = reminders.slice(0, 100);
  saveReminders(reminders);
  if (typeof renderFocusReminders === 'function') renderFocusReminders();
}

function dismissReminder(remId) {
  var reminders = getReminders();
  for (var i = 0; i < reminders.length; i++) {
    if (reminders[i].id === remId) { reminders[i].dismissed = true; break; }
  }
  saveReminders(reminders);
  if (typeof renderFocusReminders === 'function') renderFocusReminders();
}

function clearAllReminders() {
  var reminders = getReminders();
  for (var i = 0; i < reminders.length; i++) reminders[i].dismissed = true;
  saveReminders(reminders);
  if (typeof renderFocusReminders === 'function') renderFocusReminders();
}

// Quick add reminder from Focus
function addQuickReminder() {
  var title = prompt('Reminder title:');
  if (!title || !title.trim()) return;
  var message = prompt('Details (optional):') || '';
  var reminder = {
    title: title.trim(),
    message: message.trim(),
    source: 'manual',
    timestamp: new Date().toISOString()
  };
  saveReminderToHistory(reminder);
  showToast('Reminder added', 'success');
}

// v25.2: Render reminders widget in Focus view with scheduled times, overdue indicators
function renderFocusReminders() {
  var container = document.getElementById('focus2RemindersList');
  if (!container) return;
  var reminders = getReminders().filter(function(r) { return !r.dismissed && r.status !== 'completed'; });
  var now = Date.now();

  if (reminders.length === 0) {
    var emptyHtml = '<div style="color:var(--text-muted);font-size:12px;text-align:center;padding:16px;">No active reminders</div>';
    emptyHtml += renderInlineReminderForm();
    container.innerHTML = emptyHtml;
    return;
  }

  var html = '';
  reminders.slice(0, 10).forEach(function(r) {
    var scheduledAt = r.snoozedUntil || r.scheduledAt || new Date(r.timestamp).getTime();
    var isOverdue = scheduledAt && scheduledAt < now;
    var isPending = r.status === 'pending';
    var isSnoozed = r.status === 'pending' && r.snoozedUntil && r.snoozedUntil > now;

    // Time display
    var timeText = '';
    if (isSnoozed) {
      var snoozeMins = Math.ceil((r.snoozedUntil - now) / 60000);
      timeText = 'Snoozed - ' + (snoozeMins > 60 ? Math.floor(snoozeMins / 60) + 'h' : snoozeMins + 'm');
    } else if (isOverdue && isPending) {
      var overdueMins = Math.floor((now - scheduledAt) / 60000);
      timeText = 'Overdue ' + (overdueMins > 60 ? Math.floor(overdueMins / 60) + 'h ago' : overdueMins + 'm ago');
    } else if (scheduledAt > now) {
      var inMins = Math.ceil((scheduledAt - now) / 60000);
      if (inMins > 1440) timeText = 'In ' + Math.floor(inMins / 1440) + ' day' + (Math.floor(inMins / 1440) !== 1 ? 's' : '');
      else if (inMins > 60) timeText = 'In ' + Math.floor(inMins / 60) + 'h';
      else timeText = 'In ' + inMins + 'm';
    } else {
      timeText = r.timestamp ? new Date(r.timestamp).toLocaleString('en-US', { month: 'short', day: 'numeric', hour: 'numeric', minute: '2-digit' }) : '';
    }

    var borderColor = isOverdue && isPending ? '#f87171' : 'var(--accent, #a89878)';
    var sourceIcons = { manual: 'M12 6v6l4 2M12 22c5.5 0 10-4.5 10-10S17.5 2 12 2 2 6.5 2 12s4.5 10 10 10z', 'focus-inline': 'M12 6v6l4 2M12 22c5.5 0 10-4.5 10-10S17.5 2 12 2 2 6.5 2 12s4.5 10 10 10z', automation: 'M13 2L3 14h9l-1 8 10-12h-9l1-8', 'ai-chat': 'M21 15a2 2 0 01-2 2H7l-4 4V5a2 2 0 012-2h14a2 2 0 012 2z' };
    var iconPath = sourceIcons[r.source] || sourceIcons.manual;

    html += '<div style="display:flex;align-items:flex-start;gap:10px;padding:10px 0;border-bottom:1px solid var(--border-color);border-left:3px solid ' + borderColor + ';padding-left:10px;margin-left:-2px;">';
    html += '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="' + borderColor + '" stroke-width="2" style="margin-top:2px;flex-shrink:0;"><path d="' + iconPath + '"/></svg>';
    html += '<div style="flex:1;min-width:0;">';
    html += '<div style="font-size:13px;font-weight:500;color:var(--text-primary);margin-bottom:2px;">' + escapeHtml(r.title) + '</div>';
    html += '<div style="font-size:11px;color:' + (isOverdue && isPending ? '#f87171' : 'var(--text-muted)') + ';">' + timeText + '</div>';
    html += '</div>';
    if (isPending) {
      html += '<button onclick="completeReminder(\'' + r.id + '\')" style="border:none;background:none;color:var(--accent);cursor:pointer;padding:2px;flex-shrink:0;" title="Complete"><svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2"><path d="M20 6L9 17l-5-5"/></svg></button>';
    }
    html += '<button onclick="dismissReminder(\'' + r.id + '\')" style="border:none;background:none;color:var(--text-muted);cursor:pointer;padding:2px;flex-shrink:0;" title="Dismiss"><svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2"><path d="M18 6L6 18M6 6l12 12"/></svg></button>';
    html += '</div>';
  });

  html += renderInlineReminderForm();
  container.innerHTML = html;
}

function renderInlineReminderForm() {
  return '<div style="padding:10px 0 4px;border-top:1px solid var(--border-color);margin-top:4px;">'
    + '<div style="display:flex;gap:6px;align-items:center;">'
    + '<input type="text" id="focusInlineReminderTitle" placeholder="Add a reminder..." autocomplete="off" autocorrect="off" autocapitalize="off" spellcheck="false" style="flex:1;padding:6px 10px;font-size:12px;background:var(--bg-tertiary);border:1px solid var(--border-color);border-radius:var(--radius-sm);color:var(--text-primary);outline:none;" onkeydown="if(event.key===\'Enter\')submitInlineReminder();">'
    + '<input type="datetime-local" id="focusInlineReminderTime" style="padding:5px 6px;font-size:11px;background:var(--bg-tertiary);border:1px solid var(--border-color);border-radius:var(--radius-sm);color:var(--text-primary);outline:none;max-width:160px;">'
    + '<button onclick="submitInlineReminder()" style="padding:6px 10px;background:var(--brand-accent, #a89878);color:#000;border:none;border-radius:var(--radius-sm);font-size:12px;font-weight:600;cursor:pointer;white-space:nowrap;">Add</button>'
    + '</div></div>';
}

// v24.26: Handle inline reminder submission from Focus widget
function submitInlineReminder() {
  var titleInput = document.getElementById('focusInlineReminderTitle');
  var timeInput = document.getElementById('focusInlineReminderTime');
  if (!titleInput) return;
  var title = titleInput.value.trim();
  if (!title) { showToast('Please enter a reminder title', 'warning'); return; }
  // v25.2: scheduledAt from datetime picker
  var scheduledAt = Date.now();
  if (timeInput && timeInput.value) {
    scheduledAt = new Date(timeInput.value).getTime();
  }
  var reminder = {
    title: title,
    message: '',
    source: 'focus-inline',
    timestamp: new Date().toISOString(),
    scheduledAt: scheduledAt,
    status: 'pending'
  };
  saveReminderToHistory(reminder);
  titleInput.value = '';
  if (timeInput) timeInput.value = '';
  showToast('Reminder set', 'success');
}

// v25.2: Reminder Notification Popup System
var _reminderPopups = []; // Currently visible popup IDs
var _reminderQueue = []; // Queued popups waiting to show
var _reminderCheckInterval = null;
var MAX_VISIBLE_POPUPS = 3;

function startReminderChecker() {
  if (_reminderCheckInterval) return;
  _reminderCheckInterval = setInterval(checkDueReminders, 30000);
  // Also check immediately
  checkDueReminders();
}

function checkDueReminders() {
  var reminders = getReminders();
  var now = Date.now();
  var changed = false;
  for (var i = 0; i < reminders.length; i++) {
    var r = reminders[i];
    if (r.status !== 'pending') continue;
    var dueAt = r.snoozedUntil || r.scheduledAt;
    if (!dueAt || dueAt > now) continue;
    // This reminder is due
    r.status = 'fired';
    r._modifiedAt = now;
    changed = true;
    showReminderPopup(r);
    // Browser notification
    if (typeof Notification !== 'undefined' && Notification.permission === 'granted') {
      try { new Notification('RoweOS Reminder', { body: r.title, icon: '/icons/icon-192.png', tag: 'rem-' + r.id }); } catch(e) {}
    }
  }
  if (changed) saveReminders(reminders);
}

function showReminderPopup(reminder) {
  if (_reminderPopups.indexOf(reminder.id) !== -1) return; // Already showing
  if (_reminderPopups.length >= MAX_VISIBLE_POPUPS) {
    _reminderQueue.push(reminder);
    return;
  }
  _reminderPopups.push(reminder.id);

  var container = document.getElementById('reminderPopupContainer');
  if (!container) return;

  var now = Date.now();
  var scheduledAt = reminder.scheduledAt || now;
  var diffMs = now - scheduledAt;
  var timeText = '';
  var isOverdue = diffMs > 60000;
  if (isOverdue) {
    var mins = Math.floor(diffMs / 60000);
    if (mins < 60) timeText = 'Overdue by ' + mins + ' minute' + (mins !== 1 ? 's' : '');
    else timeText = 'Overdue by ' + Math.floor(mins / 60) + ' hour' + (Math.floor(mins / 60) !== 1 ? 's' : '');
  } else {
    timeText = 'Just now';
  }

  var popup = document.createElement('div');
  popup.className = 'reminder-popup';
  popup.id = 'reminderPopup_' + reminder.id;
  popup.innerHTML = '<div class="reminder-popup-header">'
    + '<span class="reminder-popup-label">RoweOS Reminder</span>'
    + '<button class="reminder-popup-close" id="remClose_' + reminder.id + '" onclick="dismissReminderPopup(\'' + reminder.id + '\')" title="Complete an action first">'
    + '<svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" stroke-width="2"><path d="M18 6L6 18M6 6l12 12"/></svg></button>'
    + '</div>'
    + '<div class="reminder-popup-title">' + escapeHtml(reminder.title) + '</div>'
    + (reminder.message ? '<div style="font-size:12px;color:var(--text-secondary);margin-bottom:6px;">' + escapeHtml(reminder.message) + '</div>' : '')
    + '<div class="reminder-popup-time' + (isOverdue ? ' overdue' : '') + '">' + timeText + '</div>'
    + '<div class="reminder-popup-actions">'
    + '<button class="reminder-popup-btn" onclick="reminderAction(\'' + reminder.id + '\',\'chat\')">Talk to AI</button>'
    + '<button class="reminder-popup-btn" onclick="reminderAction(\'' + reminder.id + '\',\'pulse\')">Add to Pulse</button>'
    + '<button class="reminder-popup-btn" onclick="reminderAction(\'' + reminder.id + '\',\'focus\')">Add to Focus</button>'
    + '<div style="position:relative;display:inline-block;">'
    + '<button class="reminder-popup-btn" onclick="toggleSnoozeMenu(\'' + reminder.id + '\')">Snooze</button>'
    + '<div class="reminder-popup-snooze-menu" id="snoozeMenu_' + reminder.id + '">'
    + '<div class="reminder-popup-snooze-option" onclick="snoozeReminder(\'' + reminder.id + '\',15)">15 minutes</div>'
    + '<div class="reminder-popup-snooze-option" onclick="snoozeReminder(\'' + reminder.id + '\',30)">30 minutes</div>'
    + '<div class="reminder-popup-snooze-option" onclick="snoozeReminder(\'' + reminder.id + '\',60)">1 hour</div>'
    + '<div class="reminder-popup-snooze-option" onclick="snoozeReminder(\'' + reminder.id + '\',180)">3 hours</div>'
    + '<div class="reminder-popup-snooze-option" onclick="snoozeReminderTomorrow(\'' + reminder.id + '\')">Tomorrow 9 AM</div>'
    + '</div></div>'
    + '<button class="reminder-popup-btn primary" onclick="completeReminder(\'' + reminder.id + '\')">Complete</button>'
    + '</div>';

  container.appendChild(popup);
  requestAnimationFrame(function() { popup.classList.add('visible'); });
}

function toggleSnoozeMenu(remId) {
  var menu = document.getElementById('snoozeMenu_' + remId);
  if (menu) menu.classList.toggle('open');
}

function enablePopupDismiss(remId) {
  var closeBtn = document.getElementById('remClose_' + remId);
  if (closeBtn) { closeBtn.classList.add('enabled'); closeBtn.title = 'Dismiss'; closeBtn.style.cursor = 'pointer'; }
}

function dismissReminderPopup(remId) {
  var closeBtn = document.getElementById('remClose_' + remId);
  if (closeBtn && !closeBtn.classList.contains('enabled')) return; // Can't dismiss yet
  var popup = document.getElementById('reminderPopup_' + remId);
  if (popup) {
    popup.classList.remove('visible');
    setTimeout(function() { if (popup.parentNode) popup.parentNode.removeChild(popup); }, 250);
  }
  _reminderPopups = _reminderPopups.filter(function(id) { return id !== remId; });
  // Show next queued
  if (_reminderQueue.length > 0) {
    var next = _reminderQueue.shift();
    showReminderPopup(next);
  }
}

function reminderAction(remId, action) {
  var reminders = getReminders();
  var reminder = null;
  for (var i = 0; i < reminders.length; i++) {
    if (reminders[i].id === remId) { reminder = reminders[i]; break; }
  }
  if (!reminder) return;

  enablePopupDismiss(remId);
  reminder.actions.push({ type: action, at: Date.now() });
  reminder._modifiedAt = Date.now();
  saveReminders(reminders);

  if (action === 'chat') {
    showView('signal');
    setTimeout(function() {
      var input = document.getElementById('chatInput') || document.getElementById('agentInput');
      if (input) { input.value = 'Regarding my reminder: ' + reminder.title; input.focus(); }
    }, 300);
  } else if (action === 'pulse') {
    if (typeof pulseGoals !== 'undefined') {
      pulseGoals.push({
        id: 'goal_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6),
        name: reminder.title,
        tasks: [],
        completed: false,
        _modifiedAt: Date.now()
      });
      if (typeof savePulseGoals === 'function') savePulseGoals();
      showToast('Added to Pulse goals', 'success');
    }
  } else if (action === 'focus') {
    showView('signal');
    if (typeof showScreen === 'function') showScreen('focus');
    showToast('Open Focus to add task', 'info');
  }
  dismissReminderPopup(remId);
}

function snoozeReminder(remId, minutes) {
  var reminders = getReminders();
  for (var i = 0; i < reminders.length; i++) {
    if (reminders[i].id === remId) {
      reminders[i].status = 'pending';
      reminders[i].snoozedUntil = Date.now() + (minutes * 60 * 1000);
      reminders[i]._modifiedAt = Date.now();
      break;
    }
  }
  saveReminders(reminders);
  enablePopupDismiss(remId);
  dismissReminderPopup(remId);
  showToast('Snoozed for ' + minutes + ' minutes', 'info');
}

function snoozeReminderTomorrow(remId) {
  var tomorrow = new Date();
  tomorrow.setDate(tomorrow.getDate() + 1);
  tomorrow.setHours(9, 0, 0, 0);
  var reminders = getReminders();
  for (var i = 0; i < reminders.length; i++) {
    if (reminders[i].id === remId) {
      reminders[i].status = 'pending';
      reminders[i].snoozedUntil = tomorrow.getTime();
      reminders[i]._modifiedAt = Date.now();
      break;
    }
  }
  saveReminders(reminders);
  enablePopupDismiss(remId);
  dismissReminderPopup(remId);
  showToast('Snoozed until tomorrow 9 AM', 'info');
}

function completeReminder(remId) {
  var reminders = getReminders();
  for (var i = 0; i < reminders.length; i++) {
    if (reminders[i].id === remId) {
      reminders[i].status = 'completed';
      reminders[i].dismissed = true;
      reminders[i]._modifiedAt = Date.now();
      break;
    }
  }
  saveReminders(reminders);
  enablePopupDismiss(remId);
  dismissReminderPopup(remId);
  if (typeof renderFocusReminders === 'function') renderFocusReminders();
  showToast('Reminder completed', 'success');
}

// v20.10: Trigger sync from NC widget, refresh display
function triggerNCSync() {
  if (!firebaseUser) { showToast('Sign in to sync', 'info'); return; }
  var syncVal = document.getElementById('ncSyncValue');
  var syncBar = document.getElementById('ncSyncBar');
  var syncSub = document.getElementById('ncSyncSub');
  var syncIcon = document.querySelector('#ncWidgetSync .nc-widget-icon');
  if (syncVal) syncVal.textContent = 'Syncing...';
  if (syncIcon) syncIcon.style.animation = 'spin 1s linear infinite';
  try {
    // v25.0: Pull from cloud (write-through handles pushes)
    loadFromFirebaseV2(false).then(function() {
      if (syncVal) syncVal.textContent = 'Just now';
      if (syncBar) { syncBar.style.width = '0%'; syncBar.style.background = '#4ade80'; }
      if (syncSub) syncSub.textContent = 'Up to date';
      if (syncIcon) syncIcon.style.animation = '';
      showToast('Synced', 'success');
    }).catch(function() {
      if (syncVal) syncVal.textContent = 'Sync failed';
      if (syncIcon) syncIcon.style.animation = '';
    });
  } catch(e) {
    if (syncVal) syncVal.textContent = 'Sync failed';
    if (syncIcon) syncIcon.style.animation = '';
  }
}

// v20.5: NC Status Widgets
function renderNCWidgets() {
  try {
    // --- Sync Widget ---
    var syncVal = document.getElementById('ncSyncValue');
    var syncBar = document.getElementById('ncSyncBar');
    var syncSub = document.getElementById('ncSyncSub');
    if (syncVal) {
      var lastSync = localStorage.getItem('roweos_last_sync');
      if (lastSync) {
        try {
          // v25.2: Handle both epoch ms (numeric string) and ISO date strings
          var syncTs = parseInt(lastSync);
          var syncDate = !isNaN(syncTs) && String(syncTs).length >= 10 ? new Date(syncTs) : new Date(lastSync);
          if (isNaN(syncDate.getTime())) throw new Error('Invalid date');
          var now = new Date();
          var diffMs = now - syncDate;
          var diffMin = Math.floor(diffMs / 60000);
          if (diffMin < 1) syncVal.textContent = 'Just now';
          else if (diffMin < 60) syncVal.textContent = diffMin + 'm ago';
          else if (diffMin < 1440) syncVal.textContent = Math.floor(diffMin / 60) + 'h ago';
          else syncVal.textContent = Math.floor(diffMin / 1440) + 'd ago';
        } catch(e) { syncVal.textContent = 'Unknown'; }
      } else {
        syncVal.textContent = 'Not synced';
      }
      // v20.10: Sync status bar — 0% right after sync, grows with time
      var syncPct = 0;
      if (lastSync) {
        try {
          // v25.2: Handle both epoch ms and ISO date strings
          var _syncTsParsed = parseInt(lastSync);
          var _syncDateObj = !isNaN(_syncTsParsed) && String(_syncTsParsed).length >= 10 ? new Date(_syncTsParsed) : new Date(lastSync);
          var _syncAge = Math.floor((new Date() - _syncDateObj) / 60000);
          // 0% at sync, 100% after 60+ minutes
          syncPct = Math.min(100, Math.round((_syncAge / 60) * 100));
        } catch(e) {}
      } else {
        syncPct = 100; // Never synced
      }
      if (syncBar) {
        syncBar.style.width = syncPct + '%';
        syncBar.style.background = syncPct > 75 ? '#fbbf24' : syncPct > 0 ? '#60a5fa' : '#4ade80';
      }
      if (syncSub) {
        syncSub.textContent = syncPct === 0 ? 'Up to date' : (syncPct >= 100 ? 'Tap to sync' : '');
      }
    }

    // --- AI Activity Widget ---
    // v20.10: Also count task history (pipelines, automations) not just chat/studio runs
    var aiVal = document.getElementById('ncAiValue');
    var aiSub = document.getElementById('ncAiSub');
    if (aiVal) {
      var runsData = null;
      try { runsData = JSON.parse(localStorage.getItem('roweos_runs') || '{}'); } catch(e) {}
      var runs = (runsData && runsData.runs) ? runsData.runs : [];
      var cmds = (runsData && runsData.agentCommands) ? runsData.agentCommands : [];
      var todayStr = new Date().toISOString().substring(0, 10);
      var todayRuns = 0;
      var lastModel = '';
      for (var r = runs.length - 1; r >= 0; r--) {
        var runDate = (runs[r].timestamp || runs[r].date || '').substring(0, 10);
        if (runDate === todayStr) {
          todayRuns++;
          if (!lastModel && runs[r].model) lastModel = runs[r].model;
        }
      }
      for (var c = cmds.length - 1; c >= 0; c--) {
        var cmdDate = (cmds[c].timestamp || cmds[c].date || '').substring(0, 10);
        if (cmdDate === todayStr) {
          todayRuns++;
          if (!lastModel && cmds[c].model) lastModel = cmds[c].model;
        }
      }
      // v20.10: Count automation/pipeline executions from task history
      try {
        var taskHist = JSON.parse(localStorage.getItem('roweos_task_history') || '[]');
        for (var th = 0; th < taskHist.length; th++) {
          var thDate = (taskHist[th].timestamp || '').substring(0, 10);
          if (thDate === todayStr) todayRuns++;
        }
      } catch(e) {}
      aiVal.textContent = todayRuns + ' run' + (todayRuns !== 1 ? 's' : '') + ' today';
      if (aiSub) {
        if (lastModel) {
          var modelName = lastModel;
          try { if (typeof getModelDisplayName === 'function') modelName = getModelDisplayName(lastModel); } catch(e) {}
          aiSub.textContent = 'Last: ' + modelName;
        } else {
          aiSub.textContent = todayRuns === 0 ? 'No activity yet' : '';
        }
      }
    }

    // --- Automations Widget ---
    // v22.8: Use getMergedAutomations() — single source of truth with deletion filtering
    var autoVal = document.getElementById('ncAutoValue');
    var autoSub = document.getElementById('ncAutoSub');
    if (autoVal) {
      var _ncTasks = typeof getMergedAutomations === 'function' ? getMergedAutomations() : [];
      var enabled = _ncTasks.filter(function(t) { return t.enabled !== false; });
      autoVal.textContent = enabled.length + ' active';

      if (autoSub && enabled.length > 0) {
        var now = new Date();
        var _todayD = now.toISOString().substring(0, 10);
        var _nowMin = now.getHours() * 60 + now.getMinutes();
        var nearest = null;
        var nearestDiff = Infinity;
        for (var i = 0; i < enabled.length; i++) {
          var t = enabled[i];
          if (!t.time) continue;
          var parts = t.time.split(':');
          var _tMin = (parseInt(parts[0]) || 0) * 60 + (parseInt(parts[1]) || 0);
          var _isRecur = t.recurType && t.recurType !== 'none' && t.recurType !== 'once';
          var _mfn; // minutes from now
          if (t.recurType === 'custom') {
            // v20.10: Custom interval — find next fixed slot from base time
            var _cInt = t.recurInterval || 1;
            var _cUnit = t.recurUnit || 'days';
            if (_cUnit === 'hours' || _cUnit === 'minutes') {
              var _intMin = _cUnit === 'hours' ? _cInt * 60 : _cInt;
              // Fixed slots: baseTime, baseTime+interval, baseTime+2*interval...
              var _elapsed = _nowMin - _tMin;
              if (_elapsed < 0) _elapsed += 1440;
              var _remaining = _intMin - (_elapsed % _intMin);
              _mfn = _remaining >= _intMin ? 0 : _remaining;
            } else {
              // Days/weeks/months — use base time, wrap to next day if past
              _mfn = _tMin - _nowMin;
              if (_mfn < -2) _mfn += 1440;
            }
          } else if (_isRecur) {
            // Daily/weekly/monthly — next occurrence at base time
            _mfn = _tMin - _nowMin;
            if (_mfn < -2) _mfn += 1440;
          } else if (t.scheduledDate) {
            if (t.scheduledDate === _todayD) {
              _mfn = _tMin - _nowMin;
              if (_mfn < -2) _mfn = Infinity; // past
            } else if (t.scheduledDate > _todayD) {
              var _fd = new Date(t.scheduledDate + 'T' + t.time + ':00');
              _mfn = Math.round((_fd - now) / 60000);
            } else { _mfn = Infinity; }
          } else {
            _mfn = _tMin - _nowMin;
            if (_mfn < -2) _mfn += 1440;
          }
          if (_mfn >= 0 && _mfn < nearestDiff) {
            nearestDiff = _mfn;
            nearest = t;
          }
        }
        if (nearest && nearestDiff < Infinity) {
          var hrs = Math.floor(nearestDiff / 60);
          var mins = nearestDiff % 60;
          var timeStr = hrs > 0 ? hrs + 'h ' + mins + 'm' : mins + 'm';
          autoSub.textContent = 'Next: ' + timeStr;
          autoSub.title = nearest.name || nearest.prompt || 'Untitled';
        } else {
          autoSub.textContent = '';
        }
      } else if (autoSub) {
        autoSub.textContent = enabled.length === 0 ? 'None scheduled' : '';
      }
    }
    // --- Scheduler Clock Widget ---
    var clockVal = document.getElementById('ncClockValue');
    var clockSub = document.getElementById('ncClockSub');
    if (clockVal) {
      if (_schedulerLastCheck) {
        var _secAgo = Math.floor((Date.now() - _schedulerLastCheck) / 1000);
        var _secLeft = Math.max(0, 60 - _secAgo);
        clockVal.textContent = _secLeft + 's';
        if (clockSub) {
          var _lastTime = new Date(_schedulerLastCheck);
          var _hh = _lastTime.getHours();
          var _mm = _lastTime.getMinutes();
          var _ampm = _hh >= 12 ? 'PM' : 'AM';
          _hh = _hh % 12 || 12;
          clockSub.textContent = 'Last: ' + _hh + ':' + String(_mm).padStart(2, '0') + ' ' + _ampm;
        }
      } else {
        clockVal.textContent = 'Starting...';
        if (clockSub) clockSub.textContent = 'Engine initializing';
      }
    }
  } catch(e) {
    console.warn('[NC Widgets] Render error:', e);
  }
}

// ═══════════════════════════════════════════════════════════════
// v20.14: PUSH NOTIFICATIONS (Web Push API + Service Worker)
// ═══════════════════════════════════════════════════════════════

var VAPID_PUBLIC_KEY = 'BMLELzogi7u53W6RoxmX9tQo4Zwm_U-p262P4fyviFqIHKOvZ4Iqa74TajPjGg3G5c_k8S5IpKw4Hd4kto1gB4M';
var _pushSwRegistration = null;

function isPushSupported() {
  return 'serviceWorker' in navigator && 'PushManager' in window && 'Notification' in window;
}

function registerServiceWorker() {
  if (!('serviceWorker' in navigator)) return Promise.resolve(null);
  return navigator.serviceWorker.register('/sw.js').then(function(reg) {
    _pushSwRegistration = reg;
    if (ROWEOS_DEBUG) console.log('[Push] Service worker registered');
    return reg;
  }).catch(function(err) {
    console.warn('[Push] Service worker registration failed:', err);
    return null;
  });
}

function initPushNotifications() {
  if (!isPushSupported()) {
    updatePushNotificationUI('not-supported');
    return;
  }
  registerServiceWorker().then(function() {
    // Check current state
    var enabled = localStorage.getItem('roweos_push_enabled') === 'true';
    var toggle = document.getElementById('pushNotificationToggle');
    if (toggle) toggle.checked = enabled;
    if (enabled && Notification.permission === 'granted') {
      updatePushNotificationUI('enabled');
      var details = document.getElementById('pushNotificationDetails');
      if (details) details.style.display = 'block';
      // v20.14: Re-subscribe moved to completeFirebaseLogin() where firebaseUser is guaranteed set
    } else if (enabled && Notification.permission === 'denied') {
      updatePushNotificationUI('denied');
      if (toggle) toggle.checked = false;
      localStorage.setItem('roweos_push_enabled', 'false');
    } else {
      updatePushNotificationUI('disabled');
    }
  });
}

function updatePushNotificationUI(state) {
  var statusEl = document.getElementById('pushNotificationStatus');
  if (!statusEl) return;
  switch (state) {
    case 'not-supported':
      statusEl.textContent = 'Not available on this device';
      statusEl.style.color = '';
      break;
    case 'enabled':
      statusEl.textContent = 'Enabled: you will receive push notifications';
      statusEl.style.color = '#4ade80';
      break;
    case 'denied':
      statusEl.textContent = 'Blocked by browser: enable in device settings';
      statusEl.style.color = '#ef4444';
      break;
    case 'disabled':
      statusEl.textContent = 'Not enabled';
      statusEl.style.color = '';
      break;
    case 'subscribing':
      statusEl.textContent = 'Setting up...';
      statusEl.style.color = '#a89878';
      break;
    default:
      statusEl.textContent = state;
      statusEl.style.color = '';
  }
}

function togglePushNotifications(enabled) {
  if (enabled) {
    if (!isPushSupported()) {
      showToast('Push notifications are not supported on this device', 'warning');
      var toggle = document.getElementById('pushNotificationToggle');
      if (toggle) toggle.checked = false;
      return;
    }
    updatePushNotificationUI('subscribing');
    subscribeToPush();
  } else {
    unsubscribeFromPush();
    localStorage.setItem('roweos_push_enabled', 'false');
    updatePushNotificationUI('disabled');
    var details = document.getElementById('pushNotificationDetails');
    if (details) details.style.display = 'none';
  }
}

function urlBase64ToUint8Array(base64String) {
  var padding = '='.repeat((4 - base64String.length % 4) % 4);
  var base64 = (base64String + padding).replace(/-/g, '+').replace(/_/g, '/');
  var rawData = atob(base64);
  var outputArray = new Uint8Array(rawData.length);
  for (var i = 0; i < rawData.length; i++) {
    outputArray[i] = rawData.charCodeAt(i);
  }
  return outputArray;
}

function subscribeToPush(silent) {
  if (!_pushSwRegistration) {
    registerServiceWorker().then(function(reg) {
      if (reg) subscribeToPush(silent);
      else {
        if (!silent) showToast('Service worker not available', 'error');
        var toggle = document.getElementById('pushNotificationToggle');
        if (toggle && !silent) toggle.checked = false;
        if (!silent) updatePushNotificationUI('disabled');
      }
    });
    return;
  }

  // v20.16: Step-by-step push subscription with diagnostics
  var _pushSilent = silent;
  var _pushFail = function(step, err) {
    console.error('[Push] Step ' + step + ' failed:', err);
    if (!_pushSilent) showToast('Push failed at step ' + step + ': ' + (err.message || err), 'error');
    var toggle = document.getElementById('pushNotificationToggle');
    if (toggle && !_pushSilent) toggle.checked = false;
    if (!_pushSilent) updatePushNotificationUI('disabled');
  };

  // Step 0: Fetch VAPID public key from server (guarantees match with private key)
  var step = 0;
  fetch('/api/push', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ action: 'vapidkey' })
  }).then(function(resp) {
    if (!resp.ok) throw new Error('Failed to fetch VAPID key: ' + resp.status);
    return resp.json();
  }).then(function(keyData) {
    var serverVapidKey = keyData.vapidKey;
    if (!serverVapidKey) throw new Error('Server returned no VAPID key');

    // v20.16: Log if server key differs from hardcoded constant
    if (serverVapidKey !== VAPID_PUBLIC_KEY) {
      console.warn('[Push] Server VAPID key differs from hardcoded! Using server key.');
      console.log('[Push] Server:    ' + serverVapidKey.substring(0, 30) + '...');
      console.log('[Push] Hardcoded: ' + VAPID_PUBLIC_KEY.substring(0, 30) + '...');
    } else {
      console.log('[Push] VAPID key verified: server matches hardcoded');
    }

    // Step 1: Request permission
    step = 1;
    return Notification.requestPermission().then(function(permission) {
      if (permission !== 'granted') {
        if (!_pushSilent) showToast('Notification permission denied', 'warning');
        var toggle = document.getElementById('pushNotificationToggle');
        if (toggle && !_pushSilent) toggle.checked = false;
        if (!_pushSilent) updatePushNotificationUI(permission === 'denied' ? 'denied' : 'disabled');
        return;
      }

      // Step 2: Get existing subscription
      step = 2;
      return _pushSwRegistration.pushManager.getSubscription().then(function(existingSub) {
        // Step 3: Unsubscribe if exists
        step = 3;
        if (existingSub) {
          console.log('[Push] Clearing existing subscription');
          return existingSub.unsubscribe();
        }
        return Promise.resolve();
      }).then(function() {
        // Step 4: Create new subscription with SERVER's VAPID key
        step = 4;
        var keyArray;
        try {
          keyArray = urlBase64ToUint8Array(serverVapidKey);
          console.log('[Push] Key converted, length:', keyArray.length, 'first byte:', keyArray[0]);
        } catch(keyErr) {
          _pushFail('4a-key', keyErr);
          return;
        }
        return _pushSwRegistration.pushManager.subscribe({
          userVisibleOnly: true,
          applicationServerKey: keyArray
        });
      }).then(function(subscription) {
        if (!subscription) return; // failed at step 4a
        // Step 5: Send to server
        step = 5;
        var subJson = subscription.toJSON();
        var uid = '';
        try { if (firebaseUser) uid = firebaseUser.uid; } catch(e) {}
        if (!uid) {
          if (!_pushSilent) showToast('Sign in to enable push notifications', 'warning');
          var toggle = document.getElementById('pushNotificationToggle');
          if (toggle && !_pushSilent) toggle.checked = false;
          if (!_pushSilent) updatePushNotificationUI('disabled');
          return;
        }
        console.log('[Push] Subscribing: uid=' + uid + ' endpoint=' + (subJson.endpoint || '').substring(0, 60));
        return fetch('/api/push', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ action: 'subscribe', uid: uid, subscription: subJson })
        }).then(function(resp) {
          step = 6;
          if (!resp.ok) {
            return resp.text().then(function(txt) {
              throw new Error('Server ' + resp.status + ': ' + txt.substring(0, 100));
            });
          }
          return resp.json();
        }).then(function(data) {
          step = 7;
          console.log('[Push] Subscribe response:', JSON.stringify(data));
          if (data.success) {
            localStorage.setItem('roweos_push_enabled', 'true');
            localStorage.setItem('roweos_push_endpoint', subJson.endpoint);
            updatePushNotificationUI('enabled');
            var details = document.getElementById('pushNotificationDetails');
            if (details) details.style.display = 'block';
            if (!_pushSilent) showToast('Push notifications enabled', 'success');
          } else {
            _pushFail('7-server', { message: data.error || 'Unknown server error' });
          }
        });
      });
    });
  }).catch(function(err) {
    _pushFail(step, err);
  });
}

function unsubscribeFromPush() {
  if (!_pushSwRegistration) return;
  _pushSwRegistration.pushManager.getSubscription().then(function(subscription) {
    if (!subscription) return;
    var endpoint = subscription.endpoint;
    subscription.unsubscribe().then(function() {
      // Remove from server
      var uid = '';
      try { if (firebaseUser) uid = firebaseUser.uid; } catch(e) {}
      if (uid) {
        fetch('/api/push', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ action: 'unsubscribe', uid: uid, endpoint: endpoint })
        }).catch(function() {});
      }
      localStorage.removeItem('roweos_push_endpoint');
      showToast('Push notifications disabled', 'info');
    });
  });
}

function sendTestPushNotification() {
  var uid = '';
  try { if (firebaseUser) uid = firebaseUser.uid; } catch(e) {}
  if (!uid) { showToast('Sign in to test notifications', 'warning'); return; }

  // v20.16: Reset all old subscriptions first, then re-subscribe fresh, then test
  showToast('Resetting push subscriptions...', 'info');
  fetch('/api/push', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ action: 'reset', uid: uid })
  }).then(function(resp) { return resp.json(); }).then(function(resetData) {
    console.log('[Push] Reset result:', JSON.stringify(resetData));
    var serverVapidKey = (resetData && resetData.vapidKey) || VAPID_PUBLIC_KEY;

    showToast('Re-subscribing with fresh key...', 'info');
    // Unsubscribe from browser push manager first
    return _pushSwRegistration.pushManager.getSubscription().then(function(existingSub) {
      if (existingSub) return existingSub.unsubscribe();
    }).then(function() {
      // Subscribe with server's VAPID key
      return _pushSwRegistration.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: urlBase64ToUint8Array(serverVapidKey)
      });
    }).then(function(subscription) {
      var subJson = subscription.toJSON();
      console.log('[Push] Fresh subscription: endpoint=' + (subJson.endpoint || '').substring(0, 60));
      // Store subscription on server
      return fetch('/api/push', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'subscribe', uid: uid, subscription: subJson })
      }).then(function(subResp) { return subResp.json(); });
    }).then(function(subData) {
      console.log('[Push] Subscribe result:', JSON.stringify(subData));
      if (!subData.success) {
        showToast('Subscribe failed: ' + (subData.error || 'Unknown'), 'error');
        return;
      }
      // Now send test
      showToast('Sending test notification...', 'info');
      return fetch('/api/push', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'test', uid: uid })
      }).then(function(testResp) { return testResp.json(); }).then(function(data) {
        if (data.success && data.sent > 0) {
          showToast('Test notification sent!', 'success');
        } else {
          showToast('Push failed: sent=' + data.sent + ' failed=' + data.failed + '. Check Vercel logs.', 'error');
        }
      });
    });
  }).catch(function(err) {
    // v20.15: iOS PWA drops fetch when backgrounded — retry once
    if (err.message === 'Load failed' && !sendTestPushNotification._retried) {
      sendTestPushNotification._retried = true;
      showToast('Retrying...', 'info');
      setTimeout(function() { sendTestPushNotification(); }, 1500);
      return;
    }
    sendTestPushNotification._retried = false;
    showToast('Test failed: ' + err.message, 'error');
  });
  sendTestPushNotification._retried = false;
}

// v20.16: Force re-subscribe then retry test notification (fetches VAPID key from server)
function _pushResubscribeAndRetryTest(uid) {
  if (!_pushSwRegistration) {
    registerServiceWorker().then(function(reg) {
      if (reg) _pushResubscribeAndRetryTest(uid);
      else showToast('Service worker not available', 'error');
    });
    return;
  }

  // v20.16: Fetch VAPID key from server first
  fetch('/api/push', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ action: 'vapidkey' })
  }).then(function(resp) { return resp.json(); }).then(function(keyData) {
    var vapidKey = keyData.vapidKey || VAPID_PUBLIC_KEY;
    console.log('[Push] Re-subscribe: using server VAPID key, len=' + vapidKey.length);

    // Clear existing subscription first
    return _pushSwRegistration.pushManager.getSubscription().then(function(existingSub) {
      if (existingSub) {
        console.log('[Push] Re-subscribe: clearing existing subscription');
        return existingSub.unsubscribe();
      }
    }).then(function() {
      return _pushSwRegistration.pushManager.subscribe({
        userVisibleOnly: true,
        applicationServerKey: urlBase64ToUint8Array(vapidKey)
      });
    });
  }).then(function(subscription) {
    var subJson = subscription.toJSON();
    console.log('[Push] Re-subscribe: endpoint=' + (subJson.endpoint || '').substring(0, 60) + '...');
    console.log('[Push] Re-subscribe: uid=' + uid);

    return fetch('/api/push', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ action: 'subscribe', uid: uid, subscription: subJson })
    }).then(function(resp) { return resp.json(); }).then(function(data) {
      console.log('[Push] Re-subscribe response:', JSON.stringify(data));
      if (data.success) {
        showToast('Re-registered. Sending test...', 'info');
        // Retry test after brief delay
        setTimeout(function() {
          fetch('/api/push', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ action: 'test', uid: uid })
          }).then(function(r) { return r.json(); }).then(function(d) {
            if (d.success && d.sent > 0) {
              showToast('Test notification sent (' + d.sent + ' device' + (d.sent === 1 ? '' : 's') + ')', 'success');
            } else {
              showToast('Still 0 devices: check Vercel logs for push API errors', 'error');
            }
          }).catch(function(e) { showToast('Retry failed: ' + e.message, 'error'); });
        }, 1500);
      } else {
        showToast('Re-register failed: ' + (data.error || 'Unknown'), 'error');
      }
    });
  }).catch(function(err) {
    console.error('[Push] Re-subscribe failed:', err);
    showToast('Push subscription failed: ' + err.message, 'error');
  });
}

// Send push notification from client (used by addNotification to also push)
function sendPushNotification(title, message, opts) {
  if (localStorage.getItem('roweos_push_enabled') !== 'true') return;
  var uid = '';
  try { if (firebaseUser) uid = firebaseUser.uid; } catch(e) {}
  if (!uid) return;

  fetch('/api/push', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      action: 'send',
      uid: uid,
      title: title || 'RoweOS',
      message: message || '',
      tag: (opts && opts.tag) || '',
      url: (opts && opts.url) || '/',
      type: (opts && opts.type) || 'general'
    })
  }).catch(function() {});
}

// v19.6: Notification Center
var _lastSyncNotifTime = 0;

function getNotifications() {
  try {
    var raw = localStorage.getItem('roweos_notifications');
    return raw ? JSON.parse(raw) : [];
  } catch(e) { return []; }
}

function saveNotifications(arr) {
  try {
    localStorage.setItem('roweos_notifications', JSON.stringify(arr));
  } catch(e) {
    // Quota fallback — trim to 50
    try {
      localStorage.setItem('roweos_notifications', JSON.stringify(arr.slice(0, 50)));
    } catch(e2) {}
  }
}

function addNotification(type, title, message, data) {
  var notifs = getNotifications();
  // v23.17: Deduplicate — skip if same task created a notification within last 5 minutes
  if (data && data.taskId) {
    var _dupeWindow = 5 * 60 * 1000;
    var _now = Date.now();
    for (var _di = 0; _di < Math.min(notifs.length, 20); _di++) {
      var _dn = notifs[_di];
      if (_dn.data && _dn.data.taskId === data.taskId && _dn.title === title && (_now - _dn.timestamp) < _dupeWindow) {
        if (localStorage.getItem('roweos_debug') === 'true') console.log('[Notifications] Skipping duplicate:', title, data.taskId);
        return _dn;
      }
    }
  }
  // v20.17: Use data.timestamp if provided (cloud results pass execution time)
  var ts = (data && data.timestamp) ? new Date(data.timestamp).getTime() : Date.now();
  if (isNaN(ts)) ts = Date.now();
  var notif = {
    id: ts + '_' + Math.random().toString(36).substr(2, 6),
    type: type || 'info',
    title: title || '',
    message: message || '',
    timestamp: ts,
    read: false,
    data: data || {}
  };
  notifs.unshift(notif);
  if (notifs.length > 100) notifs = notifs.slice(0, 100);
  saveNotifications(notifs);
  updateNotificationBadge();
  if (isNotificationPanelOpen()) renderNotificationPanelContent();
  // v23.10: Only send push when app is backgrounded AND not for automation/pipeline results
  // (user-triggered automations already show toasts; push spam on other devices is bad UX)
  var _pushSkipTypes = ['pipeline', 'automation', 'sync'];
  if (document.hidden && _pushSkipTypes.indexOf(type) === -1) {
    sendPushNotification(title, message, { type: type, tag: 'roweos-' + type });
  }
  return notif;
}

function clearNotification(id) {
  var notifs = getNotifications().filter(function(n) { return n.id !== id; });
  saveNotifications(notifs);
  updateNotificationBadge();
  if (isNotificationPanelOpen()) renderNotificationPanelContent();
}

function clearAllNotifications() {
  saveNotifications([]);
  updateNotificationBadge();
  if (isNotificationPanelOpen()) renderNotificationPanelContent();
}

function getUnreadCount() {
  var lastSeen = parseInt(localStorage.getItem('roweos_notifications_last_seen') || '0');
  var notifs = getNotifications();
  var count = 0;
  for (var i = 0; i < notifs.length; i++) {
    if (notifs[i].timestamp > lastSeen) count++;
  }
  return count;
}

function markAllNotificationsRead() {
  localStorage.setItem('roweos_notifications_last_seen', String(Date.now()));
  updateNotificationBadge();
}

function updateNotificationBadge() {
  var count = getUnreadCount();
  // Only update the main notification center badges (not per-view badges)
  var ncBadge = document.getElementById('ncBadgeSidebar');
  if (ncBadge) {
    if (count > 0) ncBadge.classList.add('has-unread');
    else ncBadge.classList.remove('has-unread');
  }
  // Also update mobile NC badge if exists
  var ncMobile = document.getElementById('ncBadgeMobile');
  if (ncMobile) {
    if (count > 0) ncMobile.classList.add('has-unread');
    else ncMobile.classList.remove('has-unread');
  }
}

// v24.13: Per-view sidebar notification dots
function updateSidebarBadges() {
  // Automations: check for completed automations since last viewed
  try {
    var autoBadge = document.getElementById('ncBadgeAutomations');
    if (autoBadge) {
      var lastSeen = parseInt(localStorage.getItem('roweos_automations_last_seen') || '0');
      var completed = [];
      try { completed = JSON.parse(localStorage.getItem('roweos_completed_automations') || '[]'); } catch(e) {}
      var hasNew = completed.some(function(c) { return new Date(c.completedAt).getTime() > lastSeen; });
      if (hasNew) autoBadge.classList.add('has-unread');
      else autoBadge.classList.remove('has-unread');
    }
  } catch(e) {}
  // Mail: check for unread inbox messages
  try {
    var mailBadge = document.getElementById('ncBadgeMail');
    if (mailBadge) {
      var hasUnread = false;
      if (typeof _mailCurrentMessages !== 'undefined' && _mailCurrentMessages) {
        var accounts = Object.keys(_mailCurrentMessages);
        for (var i = 0; i < accounts.length; i++) {
          var msgs = _mailCurrentMessages[accounts[i]] || [];
          if (msgs.some(function(m) { return m.isUnread; })) { hasUnread = true; break; }
        }
      }
      // Also check outbox for pending items
      if (!hasUnread) {
        try {
          var outbox = JSON.parse(localStorage.getItem('roweos_mail_outbox') || '[]');
          if (outbox.length > 0) hasUnread = true;
        } catch(e) {}
      }
      if (hasUnread) mailBadge.classList.add('has-unread');
      else mailBadge.classList.remove('has-unread');
    }
  } catch(e) {}
}

// Mark automations as seen when view opens
function markAutomationsViewed() {
  localStorage.setItem('roweos_automations_last_seen', String(Date.now()));
  var badge = document.getElementById('ncBadgeAutomations');
  if (badge) badge.classList.remove('has-unread');
}

function isNotificationPanelOpen() {
  var panel = document.getElementById('notificationCenterPanel');
  return panel && panel.classList.contains('open');
}

function toggleNotificationPanel() {
  // v25.2: On desktop, use search side panel instead
  if (window.innerWidth > 768) {
    var panel = document.getElementById('searchSidePanel');
    if (panel && panel.classList.contains('open')) { closeSearchPanel(); return; }
    openSearchPanel('notifications');
    return;
  }
  if (isNotificationPanelOpen()) {
    closeNotificationPanel();
  } else {
    openNotificationPanel();
  }
}

function openNotificationPanel() {
  var scrim = document.getElementById('ncScrim');
  var panel = document.getElementById('notificationCenterPanel');
  if (!scrim || !panel) return;
  renderNCWidgets();
  renderNotificationPanelContent();
  scrim.classList.add('open');
  panel.classList.add('open');
  markAllNotificationsRead();
}

function closeNotificationPanel() {
  var scrim = document.getElementById('ncScrim');
  var panel = document.getElementById('notificationCenterPanel');
  if (scrim) scrim.classList.remove('open');
  if (panel) panel.classList.remove('open');
}

function renderNotificationPanelContent() {
  var body = document.getElementById('ncBody');
  if (!body) return;

  var notifs = getNotifications();
  if (notifs.length === 0) {
    body.innerHTML = '<div class="nc-empty">' +
      '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5">' +
      '<path d="M18 8A6 6 0 0 0 6 8c0 7-3 9-3 9h18s-3-2-3-9"/>' +
      '<path d="M13.73 21a2 2 0 0 1-3.46 0"/></svg>' +
      '<div class="nc-empty-title">No notifications</div>' +
      '<div class="nc-empty-desc">Automation results and events will appear here</div>' +
      '</div>';
    return;
  }

  var lastSeen = parseInt(localStorage.getItem('roweos_notifications_last_seen') || '0');
  var awaySince = parseInt(localStorage.getItem('roweos_notifications_away_since') || '0');
  var awayNotifs = [];
  var recentNotifs = [];

  for (var i = 0; i < notifs.length; i++) {
    if (awaySince > 0 && notifs[i].timestamp > awaySince) {
      awayNotifs.push(notifs[i]);
    } else {
      recentNotifs.push(notifs[i]);
    }
  }

  var html = '';
  if (awayNotifs.length > 0) {
    html += '<div class="nc-section-title">While You Were Away</div>';
    for (var a = 0; a < awayNotifs.length; a++) {
      html += renderNotificationCard(awayNotifs[a], lastSeen);
    }
  }
  if (recentNotifs.length > 0) {
    html += '<div class="nc-section-title">Recent</div>';
    for (var r = 0; r < recentNotifs.length; r++) {
      html += renderNotificationCard(recentNotifs[r], lastSeen);
    }
  }
  body.innerHTML = html;
}

function renderNotificationCard(notif, lastSeen) {
  var isUnread = notif.timestamp > lastSeen;
  var iconClass = '';
  var iconSvg = '';
  var isClickable = false;

  switch (notif.type) {
    case 'cloud_result':
      if (notif.data && notif.data.success === false) {
        iconClass = 'nc-icon-fail';
        iconSvg = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><path d="M15 9l-6 6M9 9l6 6"/></svg>';
      } else {
        iconClass = 'nc-icon-success';
        iconSvg = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><path d="M9 12l2 2 4-4"/></svg>';
      }
      isClickable = !!(notif.data && notif.data.taskId);
      break;
    case 'sync':
      iconClass = 'nc-icon-sync';
      iconSvg = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M21.5 2v6h-6M2.5 22v-6h6"/><path d="M2.5 11.5a10 10 0 0 1 18.42-4.5M21.5 12.5a10 10 0 0 1-18.42 4.5"/></svg>';
      break;
    case 'brand_switch':
      iconClass = 'nc-icon-brand';
      iconSvg = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M22 21v-2a4 4 0 0 0-3-3.87M16 3.13a4 4 0 0 1 0 7.75"/></svg>';
      break;
    case 'pipeline':
      iconClass = 'nc-icon-pipeline';
      iconSvg = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="16 3 21 3 21 8"/><line x1="4" y1="20" x2="21" y2="3"/><polyline points="21 16 21 21 16 21"/><line x1="15" y1="15" x2="21" y2="21"/><line x1="4" y1="4" x2="9" y2="9"/></svg>';
      isClickable = !!(notif.data && notif.data.taskId);
      break;
    default:
      iconClass = 'nc-icon-sync';
      iconSvg = '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><path d="M12 16v-4M12 8h.01"/></svg>';
  }

  var timeStr = '';
  try { timeStr = getTimeAgo(new Date(notif.timestamp)); } catch(e) { timeStr = ''; }

  var clickAttr = '';
  if (isClickable) {
    clickAttr = ' onclick="ncCardClick(\'' + escapeHtml(notif.data.taskId || '') + '\')"';
  }

  return '<div class="nc-card' + (isUnread ? ' unread' : '') + (isClickable ? ' nc-clickable' : '') + '"' + clickAttr + '>' +
    '<div class="nc-card-icon ' + iconClass + '">' + iconSvg + '</div>' +
    '<div class="nc-card-content">' +
    '<div class="nc-card-title">' + escapeHtml(notif.title) + '</div>' +
    '<div class="nc-card-message">' + escapeHtml(notif.message) + '</div>' +
    (timeStr ? '<div class="nc-card-time">' + escapeHtml(timeStr) + '</div>' : '') +
    '</div>' +
    '<button class="nc-card-delete" onclick="event.stopPropagation(); clearNotification(\'' + notif.id + '\')" aria-label="Delete">' +
    '<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round"><path d="M18 6L6 18M6 6l12 12"/></svg>' +
    '</button>' +
    '</div>';
}

// v20.6: Navigate to Automations → Executions tab with history, show result detail
function ncCardClick(taskId) {
  if (!taskId) return;
  closeNotificationPanel();
  // Navigate to Automations view → Executions tab
  showView('automations');
  setTimeout(function() {
    showAutoLabTab('scheduler');
    // Highlight the relevant history entry after render
    setTimeout(function() {
      var histEl = document.getElementById('autoLabHistoryEntry_' + taskId);
      if (histEl) {
        histEl.scrollIntoView({ behavior: 'smooth', block: 'center' });
        histEl.style.outline = '2px solid var(--brand-accent, #a89878)';
        histEl.style.outlineOffset = '2px';
        setTimeout(function() { histEl.style.outline = 'none'; }, 3000);
      }
    }, 300);
  }, 100);
}

// Loading Overlay
function showLoading(message) {
  message = message || 'Loading...';
  
  var overlay = document.getElementById('loadingOverlay');
  if (!overlay) {
    overlay = document.createElement('div');
    overlay.id = 'loadingOverlay';
    overlay.className = 'loading-overlay';
    overlay.innerHTML = '<div><div class="loading-spinner"></div><div class="loading-text">' + message + '</div></div>';
    document.body.appendChild(overlay);
  } else {
    overlay.querySelector('.loading-text').textContent = message;
    overlay.style.display = 'flex';
  }
}

function hideLoading() {
  var overlay = document.getElementById('loadingOverlay');
  if (overlay) {
    overlay.style.display = 'none';
  }
}

// Keyboard Event Handler
document.addEventListener('keydown', function(e) {
  // Cmd/Ctrl + K = Search
  if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
    e.preventDefault();
    openSearch();
  }

  // v25.1: Cmd/Ctrl + = or + = zoom in; Cmd/Ctrl + - = zoom out (interface zoom)
  if ((e.metaKey || e.ctrlKey) && (e.key === '=' || e.key === '+')) {
    if (!(e.target && (e.target.matches('input, textarea') || e.target.isContentEditable || (e.target.closest && e.target.closest('[contenteditable]'))))) {
      e.preventDefault();
      try {
        var _curZoom = parseInt(localStorage.getItem('roweos_app_zoom') || '100') || 100;
        var _newZoom = Math.min(150, _curZoom + 5);
        if (typeof setAppZoom === 'function') setAppZoom(_newZoom);
      } catch(e2) {}
    }
  }
  if ((e.metaKey || e.ctrlKey) && e.key === '-') {
    if (!(e.target && (e.target.matches('input, textarea') || e.target.isContentEditable || (e.target.closest && e.target.closest('[contenteditable]'))))) {
      e.preventDefault();
      try {
        var _curZoom2 = parseInt(localStorage.getItem('roweos_app_zoom') || '100') || 100;
        var _newZoom2 = Math.max(75, _curZoom2 - 5);
        if (typeof setAppZoom === 'function') setAppZoom(_newZoom2);
      } catch(e3) {}
    }
  }
  
  // Cmd/Ctrl + N = New Brand (only when not typing)
  if ((e.metaKey || e.ctrlKey) && e.key === 'n' && !(e.target && (e.target.matches('input, textarea') || e.target.isContentEditable || (e.target.closest && e.target.closest('[contenteditable]'))))) {
    e.preventDefault();
    openModal('addBrandModal');
  }

  // Cmd/Ctrl + E = Edit Brand (only when not typing)
  if ((e.metaKey || e.ctrlKey) && e.key === 'e' && !(e.target && (e.target.matches('input, textarea') || e.target.isContentEditable || (e.target.closest && e.target.closest('[contenteditable]'))))) {
    e.preventDefault();
    openEditBrandModal();
  }
  
  // Cmd/Ctrl + B = Bold in contenteditable, or Focus Brand Selector otherwise
  if ((e.metaKey || e.ctrlKey) && e.key === 'b') {
    if (e.target && e.target.isContentEditable) {
      // v23.2: Let browser handle Ctrl+B for bold in contenteditable
      return;
    }
    e.preventDefault();
    var selector = document.getElementById('brandSelector');
    if (selector) selector.focus();
  }
  // v23.2: Ctrl+I/U in contenteditable — let browser handle natively
  if ((e.metaKey || e.ctrlKey) && (e.key === 'i' || e.key === 'u')) {
    if (e.target && e.target.isContentEditable) return;
  }
  
  // Cmd/Ctrl + \ = Toggle Sidebar
  if ((e.metaKey || e.ctrlKey) && e.key === '\\') {
    e.preventDefault();
    toggleSidebar();
  }
  
  // ? = Show Shortcuts (when not in input)
  if (e.key === '?' && !e.target.matches('input, textarea') && !(e.target.isContentEditable || (e.target.closest && e.target.closest('[contenteditable]')))) {
    e.preventDefault();
    openShortcuts();
  }
  
  // ESC = Close overlays
  if (e.key === 'Escape') {
    if (typeof isNotificationPanelOpen === 'function' && isNotificationPanelOpen()) {
      closeNotificationPanel();
      return;
    }
    closeSearch();
    closeShortcuts();
    closeModal('addBrandModal');
    closeModal('editBrandModal');
    closeModal('deleteBrandModal');
    closeModal('importExportModal');
  }
  
  // v25.1: Guard — never trigger navigation shortcuts while typing in any editable field
  var _isEditing = e.target && (e.target.matches('input, textarea') || e.target.isContentEditable || (e.target.closest && e.target.closest('[contenteditable]')));

  // G then B = Go to BrandAI
  if (lastKey === 'g' && e.key === 'b' && !_isEditing) {
    e.preventDefault();
    showView('agent');
    lastKey = '';
  }

  // G then S = Go to Studio
  if (lastKey === 'g' && e.key === 's' && !_isEditing) {
    e.preventDefault();
    showView('studio');
    lastKey = '';
  }

  // G then D = Go to Signal (Dashboard)
  if (lastKey === 'g' && e.key === 'd' && !_isEditing) {
    e.preventDefault();
    showView('signal');
    lastKey = '';
  }

  // Remember last key for sequences
  if (e.key === 'g' && !_isEditing) {
    lastKey = 'g';
    setTimeout(function() { lastKey = ''; }, 1000);
  }
});

var lastKey = '';

// Add toast slide out animation
var style = document.createElement('style');
style.textContent = '@keyframes toastSlideOut { to { transform: translateX(400px); opacity: 0; } }';
document.head.appendChild(style);


// ═══════════════════════════════════════════════════════════════
// ANALYTICS & SCHEDULE FUNCTIONS
// ═══════════════════════════════════════════════════════════════

// v25.3: Analytics Dashboard - Web Analytics via Vercel
var _analyticsData = null;
var _analyticsTab = 'website';

function switchAnalyticsTab(tab) {
  _analyticsTab = tab;
  var tabs = document.querySelectorAll('.analytics-tab');
  for (var i = 0; i < tabs.length; i++) {
    var isActive = tabs[i].getAttribute('data-tab') === tab;
    tabs[i].style.fontWeight = isActive ? '600' : '500';
    tabs[i].style.color = isActive ? 'var(--text-primary)' : 'var(--text-secondary)';
    tabs[i].style.background = isActive ? 'var(--bg-secondary)' : 'transparent';
    tabs[i].style.borderColor = isActive ? 'var(--border-color)' : 'transparent';
  }
  var websiteTab = document.getElementById('analyticsWebsiteTab');
  var socialTab = document.getElementById('analyticsSocialTab');
  if (websiteTab) websiteTab.style.display = tab === 'website' ? '' : 'none';
  if (socialTab) socialTab.style.display = tab === 'social' ? '' : 'none';
}

function loadAnalyticsDashboard() { if (typeof loadWebAnalytics === 'function') loadWebAnalytics(); }

// v25.3: Website Analytics (Vercel API)
function loadWebAnalytics() {
  var loading = document.getElementById('webAnalyticsLoading');
  var content = document.getElementById('webAnalyticsContent');
  if (loading) loading.style.display = '';
  if (content) content.style.display = 'none';

  var days = parseInt((document.getElementById('webAnalyticsTimeRange') || {}).value || '30');
  var now = new Date();
  var from = new Date(now.getTime() - days * 86400000).toISOString();
  var to = now.toISOString();

  fetch('/api/analytics?days=' + days)
    .then(function(r) { return r.json(); })
    .then(function(data) {
      if (data.error) {
        if (loading) loading.innerHTML = '<div style="color:#ef4444;">Error: ' + escapeHtml(data.error) + (data.detail ? '<br><span style="font-size:11px;color:var(--text-muted);">' + escapeHtml(data.detail).substring(0, 200) + '</span>' : '') + '</div>';
        return;
      }
      _analyticsData = data;
      renderWebAnalytics(data, days);
    })
    .catch(function(err) {
      if (loading) loading.innerHTML = '<div style="color:#ef4444;">Failed to load analytics: ' + escapeHtml(err.message) + '</div>';
    });
}

function renderWebAnalytics(data, days) {
  var loading = document.getElementById('webAnalyticsLoading');
  var content = document.getElementById('webAnalyticsContent');
  if (loading) loading.style.display = 'none';
  if (content) content.style.display = '';

  // v25.3: Parse Vercel timeseries — format: { data: { groups: { all: [{key, total, devices, bounceRate}] } } }
  var totalVisitors = 0;
  var totalPageViews = 0;
  var avgBounceRate = 0;
  var dailyData = [];
  var ts = data.timeseries || null;

  if (ts && ts.error) {
    var loading2 = document.getElementById('webAnalyticsLoading');
    if (loading2) {
      loading2.style.display = '';
      loading2.innerHTML = '<div style="color:var(--text-muted);font-size:13px;">Vercel Web Analytics not available.<br><span style="font-size:11px;">Ensure Web Analytics is enabled in your Vercel project settings.</span></div>';
    }
    if (content) content.style.display = 'none';
    return;
  }

  if (ts && ts.data && ts.data.groups && ts.data.groups.all) {
    var hourlyData = ts.data.groups.all;
    var dayMap = {};
    var bounceCount = 0;
    var bounceEntries = 0;
    hourlyData.forEach(function(h) {
      var dayKey = (h.key || '').split('T')[0];
      if (!dayKey) return;
      if (!dayMap[dayKey]) dayMap[dayKey] = { views: 0, visitors: 0 };
      dayMap[dayKey].views += (h.total || 0);
      dayMap[dayKey].visitors += (h.devices || 0);
      totalPageViews += (h.total || 0);
      totalVisitors += (h.devices || 0);
      if (h.bounceRate > 0) { bounceCount += h.bounceRate; bounceEntries++; }
    });
    avgBounceRate = bounceEntries > 0 ? Math.round(bounceCount / bounceEntries) : 0;
    var dayKeys = Object.keys(dayMap).sort();
    dayKeys.forEach(function(dk) { dailyData.push({ date: dk, views: dayMap[dk].views, visitors: dayMap[dk].visitors }); });
  }

  var viewsPerVisitor = totalVisitors > 0 ? (totalPageViews / totalVisitors).toFixed(1) : '0';

  // Summary cards
  var cardsEl = document.getElementById('webAnalyticsSummary');
  if (cardsEl) {
    cardsEl.innerHTML = renderAnalyticCard('Unique Visitors', formatAnalyticsNumber(totalVisitors), days + ' day total', '#4ade80')
      + renderAnalyticCard('Page Views', formatAnalyticsNumber(totalPageViews), days + ' day total', '#60a5fa')
      + renderAnalyticCard('Views / Visitor', viewsPerVisitor, 'average', '#a78bfa')
      + renderAnalyticCard('Bounce Rate', avgBounceRate + '%', 'average', '#fbbf24');
  }

  // Daily traffic chart (inline SVG bar chart)
  var pagesEl = document.getElementById('webAnalyticsPages');
  if (pagesEl && dailyData.length > 0) {
    var html = '<div style="font-size:14px;font-weight:600;color:var(--text-primary);margin-bottom:12px;">Daily Traffic</div>';
    var maxViews = 1;
    dailyData.forEach(function(d) { if (d.views > maxViews) maxViews = d.views; });
    var barWidth = Math.max(12, Math.floor((100 / dailyData.length) - 1));
    html += '<div style="display:flex;align-items:flex-end;gap:2px;height:120px;padding-bottom:24px;position:relative;">';
    dailyData.forEach(function(d) {
      var pct = Math.max(2, Math.round((d.views / maxViews) * 100));
      var dateLabel = d.date.split('-').slice(1).join('/');
      html += '<div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:2px;">';
      html += '<div style="font-size:9px;color:var(--text-muted);">' + d.views + '</div>';
      html += '<div style="width:100%;max-width:32px;height:' + pct + '%;background:var(--brand-accent,#a89878);border-radius:3px 3px 0 0;min-height:2px;transition:height 0.3s;"></div>';
      html += '<div style="font-size:9px;color:var(--text-muted);position:absolute;bottom:0;transform:rotate(-45deg);white-space:nowrap;">' + dateLabel + '</div>';
      html += '</div>';
    });
    html += '</div>';
    // Daily breakdown table
    html += '<div style="margin-top:16px;">';
    html += '<div style="font-size:13px;font-weight:600;color:var(--text-primary);margin-bottom:8px;">Daily Breakdown</div>';
    dailyData.slice().reverse().forEach(function(d) {
      var barPct = Math.round((d.views / maxViews) * 100);
      html += '<div style="display:flex;align-items:center;gap:12px;padding:4px 0;border-bottom:1px solid var(--border-color);">';
      html += '<div style="width:80px;font-size:12px;color:var(--text-muted);">' + d.date + '</div>';
      html += '<div style="flex:1;height:4px;border-radius:2px;background:var(--bg-tertiary);overflow:hidden;"><div style="height:100%;width:' + barPct + '%;background:var(--brand-accent,#a89878);border-radius:2px;"></div></div>';
      html += '<div style="width:50px;text-align:right;font-size:12px;font-weight:600;color:var(--text-secondary);">' + d.views + ' / ' + d.visitors + '</div>';
      html += '</div>';
    });
    html += '</div>';
    pagesEl.innerHTML = html;
  } else if (pagesEl) {
    pagesEl.innerHTML = '<div style="font-size:13px;color:var(--text-muted);padding:20px 0;text-align:center;">No traffic data for this period</div>';
  }

  // Hide breakdown panels since Vercel API doesn't expose those endpoints publicly
  var refEl = document.getElementById('webAnalyticsReferrers');
  var countryEl = document.getElementById('webAnalyticsCountries');
  var devEl = document.getElementById('webAnalyticsDevices');
  if (refEl) refEl.parentNode.style.display = 'none';
  if (devEl) devEl.style.display = 'none';
}

function renderAnalyticCard(label, value, subtitle, color) {
  return '<div style="background:var(--bg-secondary);border:1px solid var(--border-color);border-radius:var(--radius-lg);padding:16px;">'
    + '<div style="font-size:11px;color:var(--text-muted);text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px;">' + label + '</div>'
    + '<div style="font-size:28px;font-weight:700;color:' + color + ';line-height:1;">' + value + '</div>'
    + '<div style="font-size:11px;color:var(--text-muted);margin-top:4px;">' + subtitle + '</div>'
    + '</div>';
}

function formatAnalyticsNumber(n) {
  if (typeof n !== 'number') n = parseInt(n) || 0;
  if (n >= 1000000) return (n / 1000000).toFixed(1) + 'M';
  if (n >= 1000) return (n / 1000).toFixed(1) + 'K';
  return n.toString();
}

// v25.3: Backward compat stubs
function updateAnalyticsDashboard() { loadAnalyticsDashboard(); }
function exportAnalytics() { showToast('Export coming soon', 'info'); }
function clearAnalytics() { showToast('Analytics data is server-side', 'info'); }

function getAnalyticsData() {
  var data = localStorage.getItem('roweos_analytics');
  if (!data) return { entries: [] };
  try {
    return JSON.parse(data);
  } catch (e) {
    return { entries: [] };
  }
}

function saveAnalyticsData(data) {
  localStorage.setItem('roweos_analytics', JSON.stringify(data));
}

// v20.2: Per-provider spending thresholds
function saveAnalyticsThreshold(provider, val) {
  var labels = { claude: 'Anthropic', openai: 'OpenAI', gemini: 'Gemini' };
  var num = parseFloat(val);
  if (isNaN(num) || num <= 0) {
    localStorage.removeItem('roweos_analytics_threshold_' + provider);
    showToast((labels[provider] || provider) + ' threshold cleared', 'info');
  } else {
    localStorage.setItem('roweos_analytics_threshold_' + provider, String(num));
    showToast((labels[provider] || provider) + ' threshold set to $' + num.toFixed(2), 'success');
  }
  writeDB('profile/main', { analyticsThreshold: { provider: provider, value: num || null } }); // v25.1
}

function loadAnalyticsThreshold() {
  // v20.2: Migrate old global threshold to per-provider keys
  var oldGlobal = localStorage.getItem('roweos_analytics_threshold');
  if (oldGlobal && !localStorage.getItem('roweos_analytics_threshold_claude') && !localStorage.getItem('roweos_analytics_threshold_openai') && !localStorage.getItem('roweos_analytics_threshold_gemini')) {
    localStorage.setItem('roweos_analytics_threshold_claude', oldGlobal);
    localStorage.setItem('roweos_analytics_threshold_openai', oldGlobal);
    localStorage.setItem('roweos_analytics_threshold_gemini', oldGlobal);
    localStorage.removeItem('roweos_analytics_threshold');
  }
  // v20.2: Load per-provider threshold inputs
  ['claude', 'openai', 'gemini'].forEach(function(p) {
    var el = document.getElementById('analyticsThreshold_' + p);
    if (!el) return;
    var val = localStorage.getItem('roweos_analytics_threshold_' + p);
    el.value = val ? parseFloat(val) : '';
  });
}

// v24.25: Per-provider Budget/Threshold system
var _providerBudgetConfig = [
  { key: 'claude', label: 'Anthropic', color: '#a78bfa', matchKeys: ['claude', 'anthropic'] },
  { key: 'openai', label: 'OpenAI', color: '#4ade80', matchKeys: ['openai'] },
  { key: 'gemini', label: 'Gemini', color: '#60a5fa', matchKeys: ['gemini', 'google', 'nanobanana'] }
];

function getProviderBudget(provider) {
  try { return JSON.parse(localStorage.getItem('roweos_api_budget_' + provider) || 'null'); } catch(e) { return null; }
}

function saveProviderBudget(provider, data) {
  localStorage.setItem('roweos_api_budget_' + provider, JSON.stringify(data));
  writeDB('profile/main', { apiBudget: { provider: provider, data: data } }); // v25.1
}

function getProviderSpendSinceDate(provider, sinceDate) {
  var analytics = getAnalyticsData();
  var config = _providerBudgetConfig.find(function(p) { return p.key === provider; });
  if (!config) return 0;
  var total = 0;
  (analytics.entries || []).forEach(function(e) {
    if (e.timestamp >= sinceDate && config.matchKeys.indexOf(e.provider) !== -1) total += (e.cost || 0);
  });
  return total;
}

function toggleProviderMode(provider) {
  var budget = getProviderBudget(provider);
  var currentMode = (budget && budget.mode) || 'threshold';
  var newMode = currentMode === 'threshold' ? 'budget' : 'threshold';
  if (!budget) budget = {};
  budget.mode = newMode;
  saveProviderBudget(provider, budget);
  renderProviderBudgetCard(provider);
}

function saveProviderLoaded(provider, val) {
  var num = parseFloat(val);
  var budget = getProviderBudget(provider) || { mode: 'budget' };
  if (isNaN(num) || num <= 0) {
    budget.loaded = 0;
    budget.reloadDate = null;
    showToast(_providerBudgetConfig.find(function(p) { return p.key === provider; }).label + ' budget cleared', 'info');
  } else {
    budget.loaded = num;
    budget.reloadDate = Date.now();
    showToast(_providerBudgetConfig.find(function(p) { return p.key === provider; }).label + ' budget set to $' + num.toFixed(2), 'success');
  }
  saveProviderBudget(provider, budget);
  renderProviderBudgetCard(provider);
  updateOverviewBudgetCard();
}

function reloadProviderBudget(provider) {
  var budget = getProviderBudget(provider) || { mode: 'budget' };
  var inputEl = document.getElementById('providerBudgetLoaded_' + provider);
  var val = inputEl ? parseFloat(inputEl.value) : 0;
  if (!val || val <= 0) { showToast('Enter an amount first', 'warning'); return; }
  budget.loaded = val;
  budget.reloadDate = Date.now();
  budget.mode = 'budget';
  saveProviderBudget(provider, budget);
  renderProviderBudgetCard(provider);
  updateOverviewBudgetCard();
  var cfg = _providerBudgetConfig.find(function(p) { return p.key === provider; });
  showToast((cfg ? cfg.label : provider) + ' reloaded: $' + val.toFixed(2), 'success');
}

function renderProviderBudgetCard(provider) {
  var cfg = _providerBudgetConfig.find(function(p) { return p.key === provider; });
  if (!cfg) return;
  var el = document.getElementById('providerBudgetCard_' + provider);
  if (!el) return;

  var budget = getProviderBudget(provider) || {};
  var mode = budget.mode || 'threshold';
  var thresholdVal = localStorage.getItem('roweos_analytics_threshold_' + provider);

  var html = '';
  // Header with toggle
  html += '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:var(--space-3);">';
  html += '<div style="display:flex;align-items:center;gap:6px;font-size:var(--text-base);color:var(--text-tertiary);"><span style="color:' + cfg.color + ';">&#9679;</span> ' + cfg.label + '</div>';
  html += '<div style="display:flex;background:var(--bg-tertiary);border-radius:6px;overflow:hidden;border:1px solid var(--border-color);">';
  html += '<button onclick="toggleProviderMode(\'' + provider + '\')" style="padding:3px 8px;font-size:10px;border:none;cursor:pointer;background:' + (mode === 'threshold' ? 'var(--accent)' : 'transparent') + ';color:' + (mode === 'threshold' ? '#fff' : 'var(--text-muted)') + ';font-weight:600;">Threshold</button>';
  html += '<button onclick="toggleProviderMode(\'' + provider + '\')" style="padding:3px 8px;font-size:10px;border:none;cursor:pointer;background:' + (mode === 'budget' ? 'var(--accent)' : 'transparent') + ';color:' + (mode === 'budget' ? '#fff' : 'var(--text-muted)') + ';font-weight:600;">Budget</button>';
  html += '</div></div>';

  if (mode === 'threshold') {
    // v24.25: Threshold mode - now shows countdown from threshold value
    var thresholdNum = parseFloat(thresholdVal) || 0;
    // Calculate spend this calendar month
    var _monthStart = new Date(); _monthStart.setDate(1); _monthStart.setHours(0,0,0,0);
    var thresholdSpent = thresholdNum > 0 ? getProviderSpendSinceDate(provider, _monthStart.getTime()) : 0;
    var thresholdRemain = Math.max(0, thresholdNum - thresholdSpent);
    var thresholdPct = thresholdNum > 0 ? Math.min(100, (thresholdSpent / thresholdNum) * 100) : 0;
    var thresholdBarColor = thresholdRemain <= 0 ? '#ef4444' : (thresholdRemain < thresholdNum * 0.2 ? '#f59e0b' : cfg.color);

    html += '<div style="display:flex;align-items:center;gap:8px;">';
    html += '<span style="font-size:var(--text-xl);font-weight:600;color:var(--text-secondary);">$</span>';
    html += '<input type="number" id="analyticsThreshold_' + provider + '" placeholder="0.00" step="0.50" min="0" value="' + (thresholdVal || '') + '" style="background:var(--bg-tertiary);border:1px solid var(--border-color);border-radius:var(--radius-sm);padding:6px 10px;font-size:var(--text-lg);font-weight:600;color:' + cfg.color + ';width:100px;outline:none;" onchange="saveAnalyticsThreshold(\'' + provider + '\',this.value)">';
    html += '</div>';
    if (thresholdNum > 0) {
      html += '<div style="display:flex;justify-content:space-between;align-items:baseline;margin-top:8px;margin-bottom:4px;">';
      html += '<span style="font-size:var(--text-2xl);font-weight:700;color:' + thresholdBarColor + ';">$' + thresholdRemain.toFixed(2) + '</span>';
      html += '<span style="font-size:var(--text-xs);color:var(--text-muted);">$' + thresholdSpent.toFixed(2) + ' used</span>';
      html += '</div>';
      html += '<div style="height:5px;background:var(--bg-tertiary);border-radius:3px;overflow:hidden;margin-bottom:6px;">';
      html += '<div style="height:100%;width:' + thresholdPct + '%;background:' + thresholdBarColor + ';border-radius:3px;transition:width 0.3s;"></div>';
      html += '</div>';
      html += '<div style="font-size:var(--text-xs);color:var(--text-tertiary);">This month\'s usage against threshold</div>';
    } else {
      html += '<div style="font-size:var(--text-xs);color:var(--text-tertiary);margin-top:4px;">Alert when spending approaches this amount</div>';
    }
  } else {
    // Budget mode - countdown
    var loaded = budget.loaded || 0;
    var reloadDate = budget.reloadDate || Date.now();
    var spentSince = loaded > 0 ? getProviderSpendSinceDate(provider, reloadDate) : 0;
    var remaining = Math.max(0, loaded - spentSince);
    var pct = loaded > 0 ? Math.min(100, (spentSince / loaded) * 100) : 0;
    var barColor = remaining <= 0 ? '#ef4444' : (remaining < loaded * 0.2 ? '#f59e0b' : cfg.color);

    html += '<div style="display:flex;align-items:center;gap:8px;margin-bottom:8px;">';
    html += '<span style="font-size:var(--text-sm);color:var(--text-muted);">Loaded:</span>';
    html += '<span style="font-size:var(--text-secondary);font-weight:600;">$</span>';
    html += '<input type="number" id="providerBudgetLoaded_' + provider + '" placeholder="0.00" step="1" min="0" value="' + (loaded || '') + '" style="background:var(--bg-tertiary);border:1px solid var(--border-color);border-radius:var(--radius-sm);padding:4px 8px;font-size:var(--text-sm);font-weight:600;color:' + cfg.color + ';width:80px;outline:none;">';
    html += '<button onclick="reloadProviderBudget(\'' + provider + '\')" style="padding:4px 10px;font-size:10px;background:var(--bg-tertiary);border:1px solid var(--border-color);border-radius:var(--radius-sm);color:var(--text-secondary);cursor:pointer;font-weight:600;">Reload</button>';
    html += '</div>';

    if (loaded > 0) {
      html += '<div style="display:flex;justify-content:space-between;align-items:baseline;margin-bottom:4px;">';
      html += '<span style="font-size:var(--text-2xl);font-weight:700;color:' + barColor + ';">$' + remaining.toFixed(2) + '</span>';
      html += '<span style="font-size:var(--text-xs);color:var(--text-muted);">$' + spentSince.toFixed(2) + ' used</span>';
      html += '</div>';
      html += '<div style="height:5px;background:var(--bg-tertiary);border-radius:3px;overflow:hidden;margin-bottom:6px;">';
      html += '<div style="height:100%;width:' + pct + '%;background:' + barColor + ';border-radius:3px;transition:width 0.3s;"></div>';
      html += '</div>';
      var reloadStr = new Date(reloadDate).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
      html += '<div style="font-size:var(--text-xs);color:var(--text-tertiary);">Last reloaded: ' + reloadStr + '</div>';
    } else {
      html += '<div style="font-size:var(--text-xs);color:var(--text-tertiary);">Enter your API credit balance and click Reload</div>';
    }
  }

  el.innerHTML = html;
}

function renderAllProviderBudgetCards() {
  _providerBudgetConfig.forEach(function(cfg) { renderProviderBudgetCard(cfg.key); });
  updateOverviewBudgetCard();
}

function updateOverviewBudgetCard() {
  var overviewLabel = document.getElementById('commerceApiSpendLabel');
  var overviewVal = document.getElementById('commerceApiSpend');
  var overviewSub = document.getElementById('commerceApiBudgetSub');

  // Check if any provider is in budget mode
  var totalLoaded = 0;
  var totalRemaining = 0;
  var hasBudget = false;
  _providerBudgetConfig.forEach(function(cfg) {
    var budget = getProviderBudget(cfg.key);
    if (budget && budget.mode === 'budget' && budget.loaded > 0) {
      hasBudget = true;
      var spent = getProviderSpendSinceDate(cfg.key, budget.reloadDate || Date.now());
      totalLoaded += budget.loaded;
      totalRemaining += Math.max(0, budget.loaded - spent);
    }
  });

  if (!hasBudget) {
    // No budgets set - show normal spend
    var analytics = getAnalyticsData();
    var thirtyDaysAgo = Date.now() - (30 * 24 * 60 * 60 * 1000);
    var spent = 0;
    (analytics.entries || []).forEach(function(e) {
      if (e.timestamp > thirtyDaysAgo) spent += (e.cost || 0);
    });
    if (overviewLabel) overviewLabel.textContent = 'API Spend (30 Days)';
    if (overviewVal) { overviewVal.textContent = '$' + spent.toFixed(2); overviewVal.style.color = 'var(--accent)'; }
    if (overviewSub) overviewSub.style.display = 'none';
    return;
  }

  var color = totalRemaining <= 0 ? '#ef4444' : (totalRemaining < totalLoaded * 0.2 ? '#f59e0b' : '#4ade80');
  if (overviewLabel) overviewLabel.textContent = 'Budget Remaining';
  if (overviewVal) { overviewVal.textContent = '$' + totalRemaining.toFixed(2); overviewVal.style.color = color; }
  if (overviewSub) {
    overviewSub.style.display = '';
    overviewSub.textContent = '$' + (totalLoaded - totalRemaining).toFixed(2) + ' of $' + totalLoaded.toFixed(2) + ' used';
  }
}

function trackAPIUsage(provider, model, inputTokens, outputTokens, cached, webSearchUsed, context) {
  var analytics = getAnalyticsData();
  if (!analytics.entries) analytics.entries = [];

  var cost = calculateCost(provider, model, inputTokens, outputTokens, webSearchUsed);

  analytics.entries.push({
    timestamp: Date.now(),
    provider: provider,
    model: model,
    inputTokens: inputTokens,
    outputTokens: outputTokens,
    cost: cost,
    cached: cached || false,
    webSearchUsed: webSearchUsed || false,
    context: context || 'chat', // v24.18: Feature context (chat, studio, automation, image)
    brandId: parseInt(document.getElementById('agentBrand').value || document.getElementById('brand').value) || 0
  });

  // v24.18: Session cost indicator
  _sessionCostTotal = (_sessionCostTotal || 0) + cost;
  var sessionEl = document.getElementById('sessionCostDisplay');
  if (sessionEl) sessionEl.textContent = '$' + _sessionCostTotal.toFixed(4);
  
  // Keep only last 90 days
  var ninetyDaysAgo = Date.now() - (90 * 24 * 60 * 60 * 1000);
  analytics.entries = analytics.entries.filter(function(e) { return e.timestamp > ninetyDaysAgo; });
  
  saveAnalyticsData(analytics);

  // v20.2: Per-provider spending threshold check
  try {
    var providerGroups = { claude: ['claude', 'anthropic'], openai: ['openai'], gemini: ['gemini', 'google', 'nanobanana'] };
    var providerLabels = { claude: 'Anthropic', openai: 'OpenAI', gemini: 'Gemini' };
    var normKey = (provider === 'anthropic') ? 'claude' : (provider === 'google' || provider === 'nanobanana') ? 'gemini' : provider;
    var provThreshold = parseFloat(localStorage.getItem('roweos_analytics_threshold_' + normKey));
    if (provThreshold && provThreshold > 0) {
      var thirtyDaysAgo = Date.now() - (30 * 24 * 60 * 60 * 1000);
      var matchProviders = providerGroups[normKey] || [normKey];
      var provTotal = 0;
      analytics.entries.forEach(function(e) {
        if (e.timestamp > thirtyDaysAgo && matchProviders.indexOf(e.provider) !== -1) provTotal += (e.cost || 0);
      });
      if (provTotal >= provThreshold - 0.25 && provTotal < provThreshold + 0.50) {
        showToast((providerLabels[normKey] || normKey) + ' approaching threshold: $' + provTotal.toFixed(2) + ' / $' + provThreshold.toFixed(2), 'warning');
      }
    }
  } catch(e) {}

  // v24.25: Update per-provider budget countdown after each API call
  if (typeof updateOverviewBudgetCard === 'function') updateOverviewBudgetCard();
  var _budgetKey = (provider === 'anthropic') ? 'claude' : (provider === 'google' || provider === 'nanobanana') ? 'gemini' : provider;
  if (typeof renderProviderBudgetCard === 'function') renderProviderBudgetCard(_budgetKey);
}

// v15.4: Updated pricing per MTok (Feb 2026)
function calculateCost(provider, model, inputTokens, outputTokens, webSearchEnabled) {
  var pricing = {
    'claude': {
      'claude-opus-4-6': { input: 5.00, output: 25.00 },
      'claude-sonnet-4-6': { input: 3.00, output: 15.00 },
      'claude-3-5-sonnet-20241022': { input: 3.00, output: 15.00 },
      'claude-haiku-4-5-20251001': { input: 1.00, output: 5.00 }
    },
    'openai': {
      'gpt-4o': { input: 2.50, output: 10.00 },
      'gpt-4.1': { input: 2.00, output: 8.00 },
      'gpt-4o-mini': { input: 0.15, output: 0.60 },
      'gpt-5.4': { input: 2.50, output: 15.00 },
      'gpt-5.4-pro': { input: 30.00, output: 180.00 },
      'gpt-5.4-thinking': { input: 2.50, output: 15.00 },
      'o4-mini': { input: 1.10, output: 4.40 },
      'o1-preview': { input: 15.00, output: 60.00 },
      'o1-mini': { input: 3.00, output: 12.00 }
    },
    'gemini': {
      'gemini-3.1-pro-preview': { input: 2.00, output: 12.00 },
      'gemini-2.5-pro': { input: 1.25, output: 10.00 },
      'gemini-2.5-flash': { input: 0.30, output: 2.50 },
      'gemini-3-flash-preview': { input: 0.10, output: 0.40 },
      'gemini-1.5-pro': { input: 2.00, output: 12.00 }
    },
    'nanobanana': {
      'gemini-3-pro-image-preview': { perImage: 0.134 },
      'gemini-2.5-flash-image': { perImage: 0.039 },
      'gemini-2.0-flash-exp-image-generation': { perImage: 0.039 }
    }
  };

  // v15.4: Handle image generation (flat per-image cost)
  if (provider === 'nanobanana') {
    var imgRates = pricing.nanobanana && pricing.nanobanana[model];
    return imgRates ? imgRates.perImage : 0.134;
  }

  var rates = pricing[provider] && pricing[provider][model];
  if (!rates) return 0;

  var inputCost = (inputTokens / 1000000) * rates.input;
  var outputCost = (outputTokens / 1000000) * rates.output;
  var totalCost = inputCost + outputCost;

  // Add web search cost if enabled ($10 per 1000 searches for Claude)
  if (webSearchEnabled && provider === 'claude') {
    totalCost += 0.01; // $10 / 1000 = $0.01 per search
  }

  return totalCost;
}

// v15.4: Added nanobanana tracking + model-level breakdown
function calculatePeriodStats(analytics, startTime, endTime) {
  var entries = analytics.entries.filter(function(e) {
    return e.timestamp >= startTime && e.timestamp < endTime;
  });

  var stats = {
    totalCost: 0,
    totalRequests: entries.length,
    cacheHits: 0,
    providerCosts: { claude: 0, openai: 0, gemini: 0, nanobanana: 0 },
    providerRequests: { claude: 0, openai: 0, gemini: 0, nanobanana: 0 },
    contextCosts: { chat: 0, studio: 0, automation: 0, image: 0 }, // v24.18: Feature breakdown
    modelBreakdown: {},
    totalInputTokens: 0,
    totalOutputTokens: 0
  };

  entries.forEach(function(e) {
    stats.totalCost += e.cost || 0;
    if (e.cached) stats.cacheHits++;
    stats.providerCosts[e.provider] = (stats.providerCosts[e.provider] || 0) + (e.cost || 0);
    stats.providerRequests[e.provider] = (stats.providerRequests[e.provider] || 0) + 1;
    stats.totalInputTokens += e.inputTokens || 0;
    stats.totalOutputTokens += e.outputTokens || 0;
    // v24.18: Context/feature breakdown
    var ctx = e.context || 'chat';
    stats.contextCosts[ctx] = (stats.contextCosts[ctx] || 0) + (e.cost || 0);
    // Per-model breakdown
    if (!stats.modelBreakdown[e.model]) {
      stats.modelBreakdown[e.model] = { cost: 0, requests: 0, inputTokens: 0, outputTokens: 0 };
    }
    stats.modelBreakdown[e.model].cost += e.cost || 0;
    stats.modelBreakdown[e.model].requests += 1;
    stats.modelBreakdown[e.model].inputTokens += e.inputTokens || 0;
    stats.modelBreakdown[e.model].outputTokens += e.outputTokens || 0;
  });

  return stats;
}

function updateSummaryCard(id, currentValue, previousValue) {
  var el = document.getElementById(id);
  if (!el) return;
  
  if (id === 'totalSpend') {
    el.textContent = '$' + currentValue.toFixed(2);
  } else {
    el.textContent = currentValue.toLocaleString();
  }
  
  // Calculate change percentage
  var change = previousValue > 0 ? ((currentValue - previousValue) / previousValue * 100) : 0;
  var changeEl = document.getElementById(id + 'Change');
  if (changeEl) {
    var sign = change >= 0 ? '+' : '';
    changeEl.textContent = sign + change.toFixed(1) + '% from last month';
    changeEl.style.color = change > 0 ? '#a89878' : '#888';
  }
}

function updateProviderBreakdown(stats) {
  var total = stats.totalCost;
  var providers = ['claude', 'openai', 'gemini'];
  
  providers.forEach(function(provider) {
    var cost = stats.providerCosts[provider] || 0;
    var requests = stats.providerRequests[provider] || 0;
    var percentage = total > 0 ? (cost / total * 100) : 0;
    
    var costEl = document.getElementById(provider + 'Cost');
    var barEl = document.getElementById(provider + 'Bar');
    var reqEl = document.getElementById(provider + 'Requests');
    
    if (costEl) costEl.textContent = '$' + cost.toFixed(2);
    if (barEl) barEl.style.width = percentage + '%';
    if (reqEl) reqEl.textContent = requests + ' request' + (requests !== 1 ? 's' : '');
  });
}

function renderRecentActivity(analytics) {
  var container = document.getElementById('recentActivity');
  if (!container) return;
  
  var recent = analytics.entries
    .sort(function(a, b) { return b.timestamp - a.timestamp; })
    .slice(0, 10);
  
  if (recent.length === 0) {
    container.innerHTML = '<div style="text-align: center; padding: 40px; color: var(--text-tertiary);">No recent activity to display. Start using BrandAI to see analytics here.</div>';
    return;
  }
  
  var html = '<div style="display: flex; flex-direction: column; gap: var(--space-3);">';
  recent.forEach(function(entry) {
    var brand = brands[entry.brandId] || { name: 'Unknown' };
    var date = new Date(entry.timestamp);
    var providerColors = { claude: '#a89878', openai: '#10a37f', gemini: '#4285f4' };
    
    html += '<div style="display: flex; justify-content: space-between; align-items: center; padding: var(--space-3); background: var(--bg-tertiary); border-radius: var(--radius-md);">';
    html += '<div style="display: flex; align-items: center; gap: var(--space-3);">';
    html += '<div style="width: 8px; height: 8px; background: ' + providerColors[entry.provider] + '; border-radius: 50%;"></div>';
    html += '<div>';
    html += '<div style="font-weight: 500; font-size: var(--text-base);">' + brand.name + '</div>';
    html += '<div style="font-size: var(--text-sm); color: var(--text-tertiary);">' + getModelDisplayName(entry.model) + '</div>';
    html += '</div>';
    html += '</div>';
    html += '<div style="text-align: right;">';
    html += '<div style="font-weight: 600; color: var(--accent); font-size: var(--text-base);">$' + entry.cost.toFixed(4) + '</div>';
    html += '<div style="font-size: var(--text-sm); color: var(--text-tertiary);">' + formatTimeAgo(entry.timestamp) + '</div>';
    html += '</div>';
    html += '</div>';
  });
  html += '</div>';
  
  container.innerHTML = html;
}

